import {
  Controller,
  Post,
  Body,
  UseGuards,
  Get,
  Put,
  Delete,
  Param,
  Query,
  BadRequestException,
  NotFoundException,
  Req,
} from '@nestjs/common';
import { AuthGuard } from '@nestjs/passport';
import { RolesGuard } from '../auth/guards/roles.guard';
import { Roles } from '../auth/decorators/roles.decorator';
import { UserRole, User } from '../auth/entities/user.entity';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository, DataSource, In } from 'typeorm';
import * as bcrypt from 'bcrypt';
import { CreateUserDto, UpdateUserDto } from '../auth/dto/user-management.dto';
import { AuditLogService } from './audit-log.service';
import { AuditAction, AuditResource } from './entities/audit-log.entity';

@Controller('admin')
export class AdminController {
  constructor(
    @InjectRepository(User)
    private userRepository: Repository<User>,
    private dataSource: DataSource,
    private auditLogService: AuditLogService,
  ) {}

  /**
   * Migrate role enum (one-time migration)
   */
  @Post('migrate-roles')
  async migrateRoles() {
    try {
      // Add new enum value
      await this.dataSource.query(
        "ALTER TYPE users_role_enum ADD VALUE IF NOT EXISTS 'health_authority'",
      );

      // Update existing data
      const result = await this.dataSource.query(
        "UPDATE users SET role = 'health_authority' WHERE role = 'health_worker'",
      );

      return {
        success: true,
        message: 'Role migration completed',
        updated: result[1],
      };
    } catch (err: any) {
      return {
        success: false,
        error: err.message,
      };
    }
  }

  /**
   * List all admin and health authority users
   */
  @Get('users/staff')
  @UseGuards(AuthGuard('jwt'), RolesGuard)
  @Roles(UserRole.ADMIN, UserRole.HEALTH_AUTHORITY)
  async listAdminUsers(@Query('role') role?: string) {
    let where: any = [
      { role: UserRole.ADMIN },
      { role: UserRole.HEALTH_AUTHORITY },
    ];
    if (role && role !== 'ALL') {
      if (
        ![UserRole.ADMIN, UserRole.HEALTH_AUTHORITY].includes(role as UserRole)
      ) {
        throw new BadRequestException(
          'Chß╗ë hß╗ù trß╗ú vai tr├▓ admin hoß║╖c health_authority',
        );
      }
      where = { role: role as UserRole };
    }

    return this.userRepository.find({
      where,
      select: ['id', 'email', 'name', 'phone', 'role', 'isActive', 'createdAt'],
      order: { createdAt: 'DESC' },
    });
  }

  /**
   * List all users with optional filtering
   */
  @Get('users')
  @UseGuards(AuthGuard('jwt'), RolesGuard)
  @Roles(UserRole.ADMIN, UserRole.HEALTH_AUTHORITY)
  async listUsers(@Query('role') role?: string) {
    const where: any = {};
    if (role && role !== 'ALL') {
      where.role = role as UserRole;
    }

    const users = await this.userRepository.find({
      where,
      select: [
        'id',
        'email',
        'name',
        'phone',
        'role',
        'isActive',
        'createdAt',
        'updatedAt',
        'lastLoginAt',
      ],
      order: { createdAt: 'DESC' },
    });

    return users;
  }

  /**
   * Get user by ID
   */
  @Get('users/:id')
  @UseGuards(AuthGuard('jwt'), RolesGuard)
  @Roles(UserRole.ADMIN, UserRole.HEALTH_AUTHORITY)
  async getUserById(@Param('id') id: string) {
    const user = await this.userRepository.findOne({
      where: { id },
      select: [
        'id',
        'email',
        'name',
        'phone',
        'role',
        'isActive',
        'isEmailVerified',
        'isPhoneVerified',
        'createdAt',
        'updatedAt',
        'lastLoginAt',
      ],
    });

    if (!user) {
      throw new NotFoundException('User not found');
    }

    return user;
  }

  /**
   * Update user
   */
  @Put('users/:id')
  @UseGuards(AuthGuard('jwt'), RolesGuard)
  @Roles(UserRole.ADMIN)
  async updateUser(@Param('id') id: string, @Body() updateDto: UpdateUserDto) {
    const user = await this.userRepository.findOne({ where: { id } });

    if (!user) {
      throw new NotFoundException('User not found');
    }

    // Check if email/phone already exists for another user
    if (updateDto.email && updateDto.email !== user.email) {
      const existingEmail = await this.userRepository.findOne({
        where: { email: updateDto.email },
      });
      if (existingEmail && existingEmail.id !== id) {
        throw new BadRequestException('Email already exists');
      }
    }

    if (updateDto.phone && updateDto.phone !== user.phone) {
      const existingPhone = await this.userRepository.findOne({
        where: { phone: updateDto.phone },
      });
      if (existingPhone && existingPhone.id !== id) {
        throw new BadRequestException('Phone already exists');
      }
    }

    // Hash password if provided
    if (updateDto.password) {
      updateDto.password = await bcrypt.hash(updateDto.password, 10);
    }

    if (
      updateDto.role &&
      ![UserRole.ADMIN, UserRole.HEALTH_AUTHORITY].includes(updateDto.role)
    ) {
      throw new BadRequestException(
        'Trang quß║ún trß╗ï chß╗ë ─æ╞░ß╗úc tß║ío/cß║¡p nhß║¡t t├ái khoß║ún admin hoß║╖c health_authority',
      );
    }

    // Update user
    Object.assign(user, updateDto);
    await this.userRepository.save(user);

    delete user.password;
    return user;
  }

  /**
   * Delete/deactivate user
   */
  @Delete('users/:id')
  @UseGuards(AuthGuard('jwt'), RolesGuard)
  @Roles(UserRole.ADMIN)
  async deleteUser(@Param('id') id: string) {
    const user = await this.userRepository.findOne({ where: { id } });

    if (!user) {
      throw new NotFoundException('User not found');
    }

    // Soft delete by deactivating
    user.isActive = false;
    await this.userRepository.save(user);

    return { success: true, message: 'User deactivated successfully' };
  }

  /**
   * Create any user (admin, health_authority, or regular user)
   */
  @Post('users')
  @UseGuards(AuthGuard('jwt'), RolesGuard)
  @Roles(UserRole.ADMIN)
  async createUser(@Body() createDto: CreateUserDto) {
    if (![UserRole.ADMIN, UserRole.HEALTH_AUTHORITY].includes(createDto.role)) {
      throw new BadRequestException(
        'Trang quß║ún trß╗ï chß╗ë ─æ╞░ß╗úc tß║ío t├ái khoß║ún admin hoß║╖c health_authority',
      );
    }

    // Check if phone or email already exists
    const existing = await this.userRepository.findOne({
      where: [{ phone: createDto.phone }, { email: createDto.email }],
    });

    if (existing) {
      throw new BadRequestException('Phone or email already exists');
    }

    // Hash password
    const hashedPassword = await bcrypt.hash(createDto.password, 10);

    // Create user
    const user = this.userRepository.create({
      email: createDto.email,
      password: hashedPassword,
      name: createDto.name,
      phone: createDto.phone,
      role: createDto.role,
      isActive: createDto.isActive !== false,
      isEmailVerified: true,
      isPhoneVerified: true,
    });

    await this.userRepository.save(user);

    delete user.password;
    return user;
  }

  /**
   * Bootstrap: Create first admin account (no auth required, only works if no admin exists)
   */
  @Post('bootstrap')
  async bootstrapAdmin(
    @Body()
    body: {
      email: string;
      password: string;
      name: string;
      phone: string;
    },
  ) {
    // Check if any admin exists
    const adminExists = await this.userRepository.findOne({
      where: { role: UserRole.ADMIN },
    });

    if (adminExists) {
      throw new Error('Admin already exists. Use regular create endpoint.');
    }

    // Hash password
    const hashedPassword = await bcrypt.hash(body.password, 10);

    // Create first admin
    const admin = this.userRepository.create({
      email: body.email,
      password: hashedPassword,
      name: body.name,
      phone: body.phone,
      role: UserRole.ADMIN,
      isActive: true,
      isEmailVerified: true,
      isPhoneVerified: true,
    });

    await this.userRepository.save(admin);

    delete admin.password;
    return {
      success: true,
      message: 'First admin account created successfully',
      admin,
    };
  }

  /**
   * Get audit logs
   */
  @Get('audit-logs')
  @UseGuards(AuthGuard('jwt'), RolesGuard)
  @Roles(UserRole.ADMIN)
  async getAuditLogs(
    @Query('userId') userId?: string,
    @Query('action') action?: AuditAction,
    @Query('resource') resource?: AuditResource,
    @Query('page') page?: number,
    @Query('limit') limit?: number,
  ) {
    return this.auditLogService.findAll({
      userId,
      action,
      resource,
      page: page ? parseInt(String(page)) : 1,
      limit: limit ? parseInt(String(limit)) : 50,
    });
  }

  /**
   * Get recent audit activity
   */
  @Get('audit-logs/recent')
  @UseGuards(AuthGuard('jwt'), RolesGuard)
  @Roles(UserRole.ADMIN)
  async getRecentActivity(
    @Query('userId') userId?: string,
    @Query('limit') limit?: number,
  ) {
    return this.auditLogService.getRecentActivity(
      userId,
      limit ? parseInt(String(limit)) : 20,
    );
  }

  /**
   * Get audit log statistics
   */
  @Get('audit-logs/stats')
  @UseGuards(AuthGuard('jwt'), RolesGuard)
  @Roles(UserRole.ADMIN)
  async getAuditStats() {
    return this.auditLogService.getStats({});
  }
}

import {
  Controller,
  Post,
  Body,
  Get,
  Patch,
  UseGuards,
  Request,
} from '@nestjs/common';
import { AuthGuard } from '@nestjs/passport';
import { AuthService } from './auth.service';
import { RegisterDto } from './dto/register.dto';
import { LoginDto } from './dto/login.dto';
import { UpdateProfileDto } from './dto/update-profile.dto';
import { UpdateFcmTokenDto } from './dto/update-fcm-token.dto';
import { VerifyOtpDto } from './dto/verify-otp.dto';
import { ChangePasswordDto } from './dto/change-password.dto';
import { ForgotPasswordDto } from './dto/forgot-password.dto';
import { ResetPasswordDto } from './dto/reset-password.dto';

@Controller('auth')
export class AuthController {
  constructor(private readonly authService: AuthService) {}

  @Post('register')
  async register(@Body() registerDto: RegisterDto) {
    return this.authService.register(registerDto);
  }

  @Post('login')
  async login(@Body() loginDto: LoginDto) {
    return this.authService.login(loginDto);
  }

  @UseGuards(AuthGuard('jwt'))
  @Get('profile')
  async getProfile(@Request() req) {
    return this.authService.getProfile(req.user.id);
  }

  @UseGuards(AuthGuard('jwt'))
  @Patch('profile')
  async updateProfile(
    @Request() req,
    @Body() updateProfileDto: UpdateProfileDto,
  ) {
    return this.authService.updateProfile(req.user.id, updateProfileDto);
  }

  @UseGuards(AuthGuard('jwt'))
  @Post('fcm-token')
  async updateFcmToken(
    @Request() req,
    @Body() updateFcmTokenDto: UpdateFcmTokenDto,
  ) {
    await this.authService.updateFcmToken(req.user.id, updateFcmTokenDto.token);
    return { success: true };
  }

  @UseGuards(AuthGuard('jwt'))
  @Get('verify')
  async verifyToken(@Request() req) {
    return { valid: true, user: req.user };
  }

  // ==================== OTP & Verification ====================

  // Get verification status
  @UseGuards(AuthGuard('jwt'))
  @Get('verification-status')
  async getVerificationStatus(@Request() req) {
    return this.authService.getVerificationStatus(req.user.id);
  }

  // Send Email OTP
  @UseGuards(AuthGuard('jwt'))
  @Post('send-email-otp')
  async sendEmailOtp(@Request() req) {
    return this.authService.sendEmailOtp(req.user.id);
  }

  // Verify Email OTP
  @UseGuards(AuthGuard('jwt'))
  @Post('verify-email')
  async verifyEmail(@Request() req, @Body() verifyOtpDto: VerifyOtpDto) {
    return this.authService.verifyEmailOtp(req.user.id, verifyOtpDto.otp);
  }

  // Send Phone OTP
  @UseGuards(AuthGuard('jwt'))
  @Post('send-phone-otp')
  async sendPhoneOtp(@Request() req) {
    return this.authService.sendPhoneOtp(req.user.id);
  }

  // Verify Phone OTP
  @UseGuards(AuthGuard('jwt'))
  @Post('verify-phone')
  async verifyPhone(@Request() req, @Body() verifyOtpDto: VerifyOtpDto) {
    return this.authService.verifyPhoneOtp(req.user.id, verifyOtpDto.otp);
  }

  // ==================== Password Management ====================

  // Change Password (logged in user)
  @UseGuards(AuthGuard('jwt'))
  @Post('change-password')
  async changePassword(
    @Request() req,
    @Body() changePasswordDto: ChangePasswordDto,
  ) {
    return this.authService.changePassword(
      req.user.id,
      changePasswordDto.currentPassword,
      changePasswordDto.newPassword,
    );
  }

  // Forgot Password - Send OTP (public)
  @Post('forgot-password')
  async forgotPassword(@Body() forgotPasswordDto: ForgotPasswordDto) {
    return this.authService.forgotPassword(forgotPasswordDto.email);
  }

  // Reset Password with OTP (public)
  @Post('reset-password')
  async resetPassword(@Body() resetPasswordDto: ResetPasswordDto) {
    return this.authService.resetPassword(
      resetPasswordDto.email,
      resetPasswordDto.otp,
      resetPasswordDto.newPassword,
    );
  }
}

import { Module } from '@nestjs/common';
import { JwtModule } from '@nestjs/jwt';
import { PassportModule } from '@nestjs/passport';
import { TypeOrmModule } from '@nestjs/typeorm';
import { ConfigModule, ConfigService } from '@nestjs/config';
import { AuthController } from './auth.controller';
import { AuthService } from './auth.service';
import { User } from './entities/user.entity';
import { JwtStrategy } from './strategies/jwt.strategy';
import { LocalStrategy } from './strategies/local.strategy';
import { EmailService } from '../notification/email.service';
import { SmsService } from '../notification/sms.service';

@Module({
  imports: [
    TypeOrmModule.forFeature([User]),
    PassportModule.register({ defaultStrategy: 'jwt' }),
    JwtModule.registerAsync({
      imports: [ConfigModule],
      useFactory: async (configService: ConfigService) => ({
        secret:
          configService.get<string>('JWT_SECRET') || 'safezone-secret-key',
        signOptions: { expiresIn: '7d' },
      }),
      inject: [ConfigService],
    }),
  ],
  controllers: [AuthController],
  providers: [
    AuthService,
    JwtStrategy,
    LocalStrategy,
    EmailService,
    SmsService,
  ],
  exports: [AuthService, JwtModule],
})
export class AuthModule {}

import {
  Injectable,
  UnauthorizedException,
  ConflictException,
  BadRequestException,
} from '@nestjs/common';
import { JwtService } from '@nestjs/jwt';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import * as bcrypt from 'bcrypt';
import { User } from './entities/user.entity';
import { RegisterDto } from './dto/register.dto';
import { LoginDto } from './dto/login.dto';
import { UserRole } from './entities/user.entity';
import { EmailService } from '../notification/email.service';
import { SmsService } from '../notification/sms.service';

@Injectable()
export class AuthService {
  constructor(
    @InjectRepository(User)
    private userRepository: Repository<User>,
    private jwtService: JwtService,
    private emailService: EmailService,
    private smsService: SmsService,
  ) {}

  async register(
    registerDto: RegisterDto,
  ): Promise<{ user: User; token: string }> {
    const {
      email,
      password,
      name,
      phone,
      gender,
      dateOfBirth,
      citizenId,
      fullAddress,
      province,
      district,
      ward,
      consentGiven,
    } = registerDto;

    // Normalize phone number
    const normalizedPhone = this.normalizePhoneNumber(phone);

    // Check if phone already exists
    const existingPhoneUser = await this.userRepository.findOne({
      where: { phone: normalizedPhone },
    });
    if (existingPhoneUser) {
      throw new ConflictException('Sß╗æ ─æiß╗çn thoß║íi ─æ├ú ─æ╞░ß╗úc sß╗¡ dß╗Ñng');
    }

    // Check if email already exists (if provided)
    const trimmedEmail = email?.trim() || undefined;
    if (trimmedEmail) {
      const existingEmailUser = await this.userRepository.findOne({
        where: { email: trimmedEmail },
      });
      if (existingEmailUser) {
        throw new ConflictException('Email ─æ├ú ─æ╞░ß╗úc sß╗¡ dß╗Ñng');
      }
    }

    // Hash password
    const salt = await bcrypt.genSalt();
    const hashedPassword = await bcrypt.hash(password, salt);

    // Create user with enhanced fields
    const user = this.userRepository.create({
      email: trimmedEmail,
      password: hashedPassword,
      name,
      phone: normalizedPhone,
      gender,
      dateOfBirth: dateOfBirth ? new Date(dateOfBirth) : undefined,
      citizenId,
      fullAddress,
      province,
      district,
      ward,
      consentGiven: consentGiven || false,
      consentGivenAt: consentGiven ? new Date() : undefined,
    });

    await this.userRepository.save(user);

    // Generate token
    const token = this.generateToken(user);

    // Remove password from response
    delete user.password;

    return { user, token };
  }

  async login(loginDto: LoginDto): Promise<{ user: User; token: string }> {
    const { phone, email, password, source } = loginDto;

    if (!phone && !email) {
      throw new UnauthorizedException('Phß║úi cung cß║Ñp email hoß║╖c sß╗æ ─æiß╗çn thoß║íi');
    }

    let user: User | null = null;

    // Try to find user by email first
    if (email) {
      user = await this.userRepository.findOne({ where: { email } });
    }

    // If not found by email, try phone
    if (!user && phone) {
      const candidates = this.buildPhoneCandidates(phone);
      if (candidates.length > 0) {
        user = await this.userRepository.findOne({
          where: candidates.map((candidate) => ({ phone: candidate })),
        });
      }
    }

    if (!user) {
      throw new UnauthorizedException(
        'Email/Sß╗æ ─æiß╗çn thoß║íi hoß║╖c mß║¡t khß║⌐u kh├┤ng ─æ├║ng',
      );
    }

    // Role-based access control: regular users cannot log into admin web
    if (source === 'web' && user.role === UserRole.USER) {
      throw new UnauthorizedException(
        'T├ái khoß║ún ng╞░ß╗¥i d├╣ng kh├┤ng c├│ quyß╗ün truy cß║¡p trang quß║ún trß╗ï. Vui l├▓ng sß╗¡ dß╗Ñng ß╗⌐ng dß╗Ñng di ─æß╗Öng.',
      );
    }

    // Check if user is blacklisted
    if (user.isBlacklisted) {
      throw new UnauthorizedException(
        'T├ái khoß║ún cß╗ºa bß║ín ─æ├ú bß╗ï kh├│a. L├╜ do: ' +
          (user.blacklistReason || 'Vi phß║ím quy ─æß╗ïnh'),
      );
    }

    // Check if user is active
    if (!user.isActive) {
      throw new UnauthorizedException('T├ái khoß║ún cß╗ºa bß║ín ─æ├ú bß╗ï v├┤ hiß╗çu h├│a');
    }

    // Validate password
    const isPasswordValid = await bcrypt.compare(password, user.password!);
    if (!isPasswordValid) {
      throw new UnauthorizedException(
        'Email/Sß╗æ ─æiß╗çn thoß║íi hoß║╖c mß║¡t khß║⌐u kh├┤ng ─æ├║ng',
      );
    }

    // Update last login
    user.lastLoginAt = new Date();
    await this.userRepository.save(user);

    // Generate token
    const token = this.generateToken(user);

    // Remove password from response
    delete user.password;

    return { user, token };
  }

  async validateUser(userId: string): Promise<User | null> {
    const user = await this.userRepository.findOne({ where: { id: userId } });
    if (!user) return null;
    delete user.password;
    return user;
  }

  async getProfile(userId: string): Promise<User> {
    const user = await this.userRepository.findOne({ where: { id: userId } });
    if (!user) {
      throw new UnauthorizedException('Ng╞░ß╗¥i d├╣ng kh├┤ng tß╗ôn tß║íi');
    }
    delete user.password;
    return user;
  }

  async updateProfile(userId: string, dto: Record<string, any>): Promise<User> {
    const user = await this.userRepository.findOne({ where: { id: userId } });
    if (!user) {
      throw new UnauthorizedException('Ng╞░ß╗¥i d├╣ng kh├┤ng tß╗ôn tß║íi');
    }

    // Convert dateOfBirth string to Date if present
    const updateData: Partial<User> = { ...dto } as any;
    if (dto.dateOfBirth && typeof dto.dateOfBirth === 'string') {
      updateData.dateOfBirth = new Date(dto.dateOfBirth);
    }

    // Don't allow password update through this method
    delete updateData.password;
    delete updateData.email;
    delete updateData.id;

    // If phone is being updated, check if it's already used by another user
    if (updateData.phone && updateData.phone !== user.phone) {
      const normalizedPhone = this.normalizePhoneNumber(updateData.phone);
      updateData.phone = normalizedPhone;

      const existingUser = await this.userRepository.findOne({
        where: { phone: normalizedPhone },
      });
      if (existingUser && existingUser.id !== userId) {
        throw new ConflictException(
          'Sß╗æ ─æiß╗çn thoß║íi ─æ├ú ─æ╞░ß╗úc sß╗¡ dß╗Ñng bß╗ƒi t├ái khoß║ún kh├íc',
        );
      }

      // Reset phone verification when phone changes
      updateData.isPhoneVerified = false;
    }

    Object.assign(user, updateData);
    await this.userRepository.save(user);

    delete user.password;
    return user;
  }

  async updateFcmToken(userId: string, fcmToken: string): Promise<void> {
    await this.userRepository.update(userId, { fcmToken });
  }

  // Generate 6-digit OTP
  private generateOtp(): string {
    return Math.floor(100000 + Math.random() * 900000).toString();
  }

  // Get verification status
  // Reporting is allowed when at least one channel (email or phone) is verified.
  async getVerificationStatus(userId: string): Promise<{
    isEmailVerified: boolean;
    isPhoneVerified: boolean;
    isFullyVerified: boolean;
    canReport: boolean;
    email: string | null;
    phone: string;
  }> {
    const user = await this.userRepository.findOne({ where: { id: userId } });
    if (!user) {
      throw new UnauthorizedException('Ng╞░ß╗¥i d├╣ng kh├┤ng tß╗ôn tß║íi');
    }

    return {
      isEmailVerified: user.isEmailVerified,
      isPhoneVerified: user.isPhoneVerified,
      isFullyVerified: user.isEmailVerified && user.isPhoneVerified,
      canReport: user.isEmailVerified || user.isPhoneVerified,
      email: user.email || null,
      phone: user.phone,
    };
  }

  // Send Email OTP
  async sendEmailOtp(userId: string): Promise<{ message: string }> {
    const user = await this.userRepository.findOne({ where: { id: userId } });
    if (!user) {
      throw new UnauthorizedException('Ng╞░ß╗¥i d├╣ng kh├┤ng tß╗ôn tß║íi');
    }

    if (!user.email) {
      throw new BadRequestException('Ch╞░a cß║¡p nhß║¡t email');
