    const result = await this.gisService.archiveCases(dto);

    this.auditLogService.log(
      req.user.id,
      AuditAction.UPDATE,
      AuditResource.CASE,
      'bulk',
      `Archived cases (bulk)`,
      { filter: dto, affected: result.affected },
