  async unarchiveCases(@Body() dto: ArchiveCasesDto, @Req() req: any) {
    const result = await this.gisService.unarchiveCases(dto);

    this.auditLogService.log(
      req.user.id,
      AuditAction.UPDATE,
      AuditResource.CASE,
      'bulk',
      `Unarchived cases (bulk)`,
      { filter: dto, affected: result.affected },
