    @Query('status') status?: string,
    @Query('from') from?: string,
    @Query('to') to?: string,
    @Query('gridSize') gridSize?: string,
    @Query('north') north?: string,
    @Query('south') south?: string,
    @Query('east') east?: string,
    @Query('west') west?: string,
