  @Get('clusters')
  getClusteredCases(
    @Query('diseaseType') diseaseType?: string,
    @Query('status') status?: string,
    @Query('from') from?: string,
    @Query('to') to?: string,
    @Query('clusterDistance') clusterDistance?: string,
