import { Inject, Injectable, NotFoundException } from '@nestjs/common';
import { DataSource } from 'typeorm';
import { getDataSourceToken } from '@nestjs/typeorm';

export interface CaseDto {
  id?: string;
  external_id?: string;
  disease_type: string;
  status: string;
  severity?: number;
  reported_time: string;
  lat: number;
  lon: number;
  region_id?: number;
  patient_name?: string;
  patient_age?: number;
  patient_gender?: string;
  notes?: string;
  outbreak_id?: string;
}

export interface ReverseGeocodeResult {
  address: string;
  commune?: string;
  district?: string;
  province?: string;
  regionId?: number;
}

@Injectable()
export class GisService {
  constructor(
    @Inject(getDataSourceToken())
    private readonly dataSource: DataSource,
  ) {}

  private normalizeStatusForDb(status?: string) {
    if (!status) return status;
    return status === 'deceased' ? 'died' : status;
  }

  private normalizeStatusForApi(status?: string) {
    if (!status) return status;
    return status === 'died' ? 'deceased' : status;
  }

  private async resolveOutbreakIdForCase(params: {
    diseaseType: string;
    reportedTime: string;
  }): Promise<string | null> {
    const { diseaseType, reportedTime } = params;

    // disease_type in cases is a free text; we only auto-link outbreaks for diseases in catalog
    const diseaseRows = await this.dataSource.query(
      `SELECT id FROM diseases WHERE name = $1 LIMIT 1`,
      [diseaseType],
    );
    const diseaseId = diseaseRows?.[0]?.id as string | undefined;
    if (!diseaseId) return null;

    const activeRows = await this.dataSource.query(
      `
      SELECT id
      FROM disease_outbreaks
      WHERE disease_id = $1 AND status = 'active'
      ORDER BY start_date DESC
      LIMIT 1
      `,
      [diseaseId],
    );
    const activeId = activeRows?.[0]?.id as string | undefined;
    if (activeId) return activeId;

    // No active outbreak yet => create one so existing flows keep working.
    try {
      const [created] = await this.dataSource.query(
        `
        INSERT INTO disease_outbreaks (disease_id, start_date, status, created_at, updated_at)
        VALUES ($1, $2::timestamptz, 'active', now(), now())
        RETURNING id
        `,
        [diseaseId, reportedTime],
      );
      return created?.id ?? null;
    } catch {
      // In case of race (unique active index), just read again.
      const retry = await this.dataSource.query(
        `
        SELECT id
        FROM disease_outbreaks
        WHERE disease_id = $1 AND status = 'active'
        ORDER BY start_date DESC
        LIMIT 1
        `,
        [diseaseId],
      );
      return retry?.[0]?.id ?? null;
    }
  }

  async archiveCases(params: {
    diseaseType?: string;
    from?: string;
    to?: string;
    outbreakId?: string;
  }): Promise<{ affected: number }> {
    const { diseaseType, from, to, outbreakId } = params;
    const where: string[] = ['c.is_archived IS NOT TRUE'];
    const values: any[] = [];

    if (diseaseType) {
      values.push(diseaseType);
      where.push(`c.disease_type = $${values.length}`);
    }
    if (from) {
      values.push(from);
      where.push(`c.reported_time >= $${values.length}::timestamptz`);
    }
    if (to) {
      values.push(to);
      where.push(`c.reported_time <= $${values.length}::timestamptz`);
    }
    if (outbreakId) {
      values.push(outbreakId);
      where.push(`
        EXISTS (
          SELECT 1
          FROM disease_outbreaks o
          JOIN diseases d ON d.id = o.disease_id
          WHERE o.id = $${values.length}
            AND c.disease_type = d.name
            AND c.reported_time >= o.start_date
            AND (o.end_date IS NULL OR c.reported_time <= o.end_date)
        )
      `);
    }

    const [row] = await this.dataSource.query(
      `
      WITH updated AS (
        UPDATE cases c
        SET is_archived = true,
            archived_at = now()
        WHERE ${where.join(' AND ')}
        RETURNING 1
      )
      SELECT COUNT(*)::int AS affected FROM updated
      `,
      values,
    );

    return { affected: Number(row?.affected ?? 0) };
  }

  async unarchiveCases(params: {
    diseaseType?: string;
    from?: string;
    to?: string;
    outbreakId?: string;
  }): Promise<{ affected: number }> {
    const { diseaseType, from, to, outbreakId } = params;
    const where: string[] = ['c.is_archived IS TRUE'];
    const values: any[] = [];

    if (diseaseType) {
      values.push(diseaseType);
      where.push(`c.disease_type = $${values.length}`);
    }
    if (from) {
      values.push(from);
      where.push(`c.reported_time >= $${values.length}::timestamptz`);
    }
    if (to) {
      values.push(to);
      where.push(`c.reported_time <= $${values.length}::timestamptz`);
    }
    if (outbreakId) {
      values.push(outbreakId);
      where.push(`
        EXISTS (
          SELECT 1
          FROM disease_outbreaks o
          JOIN diseases d ON d.id = o.disease_id
          WHERE o.id = $${values.length}
            AND c.disease_type = d.name
            AND c.reported_time >= o.start_date
            AND (o.end_date IS NULL OR c.reported_time <= o.end_date)
        )
      `);
    }

    const [row] = await this.dataSource.query(
      `
      WITH updated AS (
        UPDATE cases c
        SET is_archived = false,
            archived_at = NULL
        WHERE ${where.join(' AND ')}
        RETURNING 1
      )
      SELECT COUNT(*)::int AS affected FROM updated
      `,
      values,
    );

    return { affected: Number(row?.affected ?? 0) };
  }

  async getRegionsGeoJSON() {
    const [row] = await this.dataSource.query(`
      SELECT jsonb_build_object(
        'type','FeatureCollection',
        'features', COALESCE(jsonb_agg(
          jsonb_build_object(
            'type','Feature',
            'geometry', ST_AsGeoJSON(r.geom)::jsonb,
            'properties', to_jsonb(r) - 'geom'
          )
        ), '[]'::jsonb)
      ) AS geojson
      FROM regions r;
    `);

    return row.geojson;
  }

  async getCasesGeoJSON(params: {
    diseaseType?: string;
    status?: string;
    from?: string;
    to?: string;
    outbreakId?: string;
    includeArchived?: boolean;
  }) {
    const { diseaseType, status, from, to, outbreakId, includeArchived } =
      params;

    const where: string[] = [];
    const values: any[] = [];

    if (!includeArchived) {
      where.push(`c.is_archived IS NOT TRUE`);
    }

    if (diseaseType) {
      values.push(diseaseType);
      where.push(`c.disease_type = $${values.length}`);
    }
    if (status) {
      values.push(this.normalizeStatusForDb(status));
      where.push(`c.status = $${values.length}`);
    }
    if (from) {
      values.push(from);
      where.push(`c.reported_time >= $${values.length}::timestamptz`);
    }
    if (to) {
      values.push(to);
      where.push(`c.reported_time <= $${values.length}::timestamptz`);
    }

    if (outbreakId) {
      values.push(outbreakId);
      where.push(`
        EXISTS (
          SELECT 1
          FROM disease_outbreaks o
          JOIN diseases d ON d.id = o.disease_id
          WHERE o.id = $${values.length}
            AND c.disease_type = d.name
            AND c.reported_time >= o.start_date
            AND (o.end_date IS NULL OR c.reported_time <= o.end_date)
        )
      `);
    }

    const whereSql = where.length ? `WHERE ${where.join(' AND ')}` : '';

    const [row] = await this.dataSource.query(
      `
      SELECT jsonb_build_object(
        'type','FeatureCollection',
        'features', COALESCE(jsonb_agg(
          jsonb_build_object(
            'type','Feature',
            'geometry', ST_AsGeoJSON(c.geom)::jsonb,
            'properties', jsonb_build_object(
              'id', c.id,
              'external_id', c.external_id,
              'disease_type', c.disease_type,
              'status', CASE WHEN c.status = 'died' THEN 'deceased' ELSE c.status END,
              'reported_time', c.reported_time,
              'region_id', c.region_id,
              'severity', c.severity,
              'region_name', COALESCE(r."TinhThanh", c.admin_unit_text),
              'patient_name', c.patient_name,
              'patient_age', c.patient_age,
              'patient_gender', c.patient_gender,
              'notes', c.notes,
              'outbreak_id', c.outbreak_id,
              'is_archived', COALESCE(c.is_archived, false),
              'lat', ST_Y(c.geom::geometry),
              'lon', ST_X(c.geom::geometry)
            )
          )
        ), '[]'::jsonb)
      ) AS geojson
      FROM cases c
      LEFT JOIN regions r ON r.id = c.region_id
      ${whereSql};
      `,
      values,
    );

    return row.geojson;
  }

