  async getCasesList(params: {
    diseaseType?: string;
    status?: string;
    from?: string;
    to?: string;
    page?: number;
    limit?: number;
    search?: string;
    outbreakId?: string;
    includeArchived?: boolean;
  }) {
    const {
      diseaseType,
      status,
      from,
      to,
      page = 1,
      limit = 50,
      search,
      outbreakId,
      includeArchived,
    } = params;

    const where: string[] = [];
    const values: any[] = [];

    if (!includeArchived) {
      where.push(`c.is_archived IS NOT TRUE`);
    }

    if (diseaseType) {
      values.push(diseaseType);
      where.push(`c.disease_type = $${values.length}`);
    }
    if (status) {
      values.push(this.normalizeStatusForDb(status));
      where.push(`c.status = $${values.length}`);
    }
    if (from) {
      values.push(from);
      where.push(`c.reported_time >= $${values.length}::timestamptz`);
    }
    if (to) {
      values.push(to);
      where.push(`c.reported_time <= $${values.length}::timestamptz`);
    }
    if (search) {
      values.push(`%${search}%`);
      where.push(
        `(c.external_id ILIKE $${values.length} OR c.patient_name ILIKE $${values.length})`,
      );
    }

    if (outbreakId) {
      values.push(outbreakId);
      where.push(`
        EXISTS (
          SELECT 1
          FROM disease_outbreaks o
          JOIN diseases d ON d.id = o.disease_id
          WHERE o.id = $${values.length}
            AND c.disease_type = d.name
            AND c.reported_time >= o.start_date
            AND (o.end_date IS NULL OR c.reported_time <= o.end_date)
        )
      `);
    }

    const whereSql = where.length ? `WHERE ${where.join(' AND ')}` : '';
    const offset = (page - 1) * limit;

    // Get total count
    const [countResult] = await this.dataSource.query(
      `SELECT COUNT(*)::int AS total FROM cases c ${whereSql}`,
      values,
    );

    // Get paginated data
    const rows = await this.dataSource.query(
      `
      SELECT
        c.id,
        c.external_id,
        c.disease_type,
        CASE WHEN c.status = 'died' THEN 'deceased' ELSE c.status END AS status,
        c.severity,
        c.reported_time,
        c.region_id,
        c.patient_name,
        c.patient_age,
        c.patient_gender,
        c.notes,
        c.outbreak_id,
        COALESCE(c.is_archived, false) AS is_archived,
        c.archived_at,
        ST_Y(c.geom::geometry) AS lat,
        ST_X(c.geom::geometry) AS lon,
        COALESCE(r."TinhThanh", c.admin_unit_text) AS region_name
      FROM cases c
      LEFT JOIN regions r ON r.id = c.region_id
      ${whereSql}
      ORDER BY c.reported_time DESC
      LIMIT $${values.length + 1} OFFSET $${values.length + 2}
      `,
      [...values, limit, offset],
    );

    return {
      data: rows,
      total: countResult.total,
      page,
      limit,
      totalPages: Math.ceil(countResult.total / limit),
    };
  }

  async createCase(dto: CaseDto) {
    const {
      disease_type,
      status,
      severity = 1,
      reported_time,
      lat,
      lon,
      region_id,
      patient_name,
      patient_age,
      patient_gender,
      notes,
    } = dto;

    const dbStatus = this.normalizeStatusForDb(status);

    const outbreakId =
      dto.outbreak_id ??
      (await this.resolveOutbreakIdForCase({
        diseaseType: disease_type,
        reportedTime: reported_time,
      }));

    const [result] = await this.dataSource.query(
      `
      WITH inserted AS (
        INSERT INTO cases (
          disease_type, status, severity, reported_time, geom, 
          region_id, admin_unit_text, patient_name, patient_age, patient_gender, notes,
          outbreak_id
        )
        VALUES (
          $1, $2, $3, $4::timestamptz, ST_SetSRID(ST_MakePoint($5, $6), 4326),
          COALESCE(
            $7, 
            (SELECT id FROM regions WHERE ST_Contains(geom, ST_SetSRID(ST_MakePoint($5, $6), 4326)) LIMIT 1)
          ),
          (SELECT "TinhThanh" FROM regions WHERE ST_Contains(geom, ST_SetSRID(ST_MakePoint($5, $6), 4326)) LIMIT 1),
          $8, $9, $10, $11,
          $12
        )
        RETURNING *
      )
      SELECT id, external_id, disease_type, status, severity, reported_time, region_id, admin_unit_text, patient_name, patient_age, patient_gender, notes, outbreak_id, COALESCE(is_archived, false) AS is_archived, archived_at
      FROM inserted
      `,
      [
        disease_type,
        dbStatus,
        severity,
        reported_time,
        lon,
        lat,
        region_id || null,
        patient_name || null,
        patient_age || null,
        patient_gender || null,
        notes || null,
        outbreakId,
      ],
    );

    return {
      ...result,
      status: this.normalizeStatusForApi(result.status),
    };
  }

  async updateCase(id: string, dto: Partial<CaseDto>) {
    const existing = await this.getCaseById(id);
    if (!existing) throw new NotFoundException(`Case with ID ${id} not found`);

    const updates: string[] = [];
    const values: any[] = [];

    const push = (val: any) => {
      values.push(val);
      return `$${values.length}`;
    };

    if (dto.disease_type !== undefined)
      updates.push(`disease_type = ${push(dto.disease_type)}`);
    if (dto.status !== undefined)
      updates.push(`status = ${push(this.normalizeStatusForDb(dto.status))}`);
    if (dto.severity !== undefined)
      updates.push(`severity = ${push(dto.severity)}`);

    if (dto.reported_time !== undefined) {
      updates.push(`reported_time = ${push(dto.reported_time)}::timestamptz`);
    }

    // notes/patient
    if (dto.patient_name !== undefined)
      updates.push(`patient_name = ${push(dto.patient_name)}`);
    if (dto.patient_age !== undefined)
      updates.push(`patient_age = ${push(dto.patient_age)}`);
    if (dto.patient_gender !== undefined)
      updates.push(`patient_gender = ${push(dto.patient_gender)}`);
    if (dto.notes !== undefined) updates.push(`notes = ${push(dto.notes)}`);

    if (dto.outbreak_id !== undefined)
      updates.push(`outbreak_id = ${push(dto.outbreak_id)}`);

    // geom + region_id logic
    const hasLat = dto.lat !== undefined;
    const hasLon = dto.lon !== undefined;

    let newPointSql: string | null = null;

    if (hasLat && hasLon) {
      const lonParam = push(dto.lon);
      const latParam = push(dto.lat);
      newPointSql = `ST_SetSRID(ST_MakePoint(${lonParam}, ${latParam}), 4326)`;

      updates.push(`geom = ${newPointSql}`);

      // Nß║┐u user kh├┤ng truyß╗ün region_id, tß╗▒ g├ín theo ST_Within(newPoint)
      if (dto.region_id === undefined) {
        updates.push(
          `
        region_id = (
          SELECT r.id
          FROM regions r
          WHERE ST_Within(${newPointSql}, r.geom)
          LIMIT 1
        ),
        admin_unit_text = (
          SELECT r."TinhThanh"
          FROM regions r
          WHERE ST_Within(${newPointSql}, r.geom)
          LIMIT 1
        )
      `.trim(),
        );
      }
    } else if (hasLat !== hasLon) {
      // tr├ính update nß╗¡a vß╗¥i
      throw new Error('Please provide both lat and lon to update location.');
    }

    // nß║┐u region_id ─æ╞░ß╗úc truyß╗ün explicit th├¼ ╞░u ti├¬n theo dto
    if (dto.region_id !== undefined)
      updates.push(`region_id = ${push(dto.region_id)}`);

    if (updates.length === 0) return existing;

    // WHERE id
    const idParam = push(id);

    await this.dataSource.query(
      `UPDATE cases SET ${updates.join(', ')} WHERE id = ${idParam}`,
      values,
    );

    return this.getCaseById(id);
  }

  async deleteCase(id: string) {
    const existing = await this.getCaseById(id);
    if (!existing) throw new NotFoundException(`Case with ID ${id} not found`);

    await this.dataSource.query(`DELETE FROM cases WHERE id = $1`, [id]);
    return { deleted: true, id };
  }

  async getStats(params: {
    diseaseType?: string;
    regionName?: string;
    status?: string;
    from?: string;
    to?: string;
    outbreakId?: string;
    includeArchived?: boolean;
  }) {
    const {
      diseaseType,
      regionName,
      status,
      from,
      to,
      outbreakId,
      includeArchived,
    } = params;

    const where: string[] = [];
    const values: any[] = [];

    if (!includeArchived) {
      where.push(`c.is_archived IS NOT TRUE`);
    }

    if (diseaseType) {
      values.push(diseaseType);
      where.push(`c.disease_type = $${values.length}`);
    }
    if (regionName) {
      values.push(regionName);
      where.push(`(
        c.admin_unit_text = $${values.length}
        OR c.region_id IN (SELECT id FROM regions WHERE "TinhThanh" = $${values.length})
      )`);
    }
    if (status) {
      values.push(this.normalizeStatusForDb(status));
      where.push(`c.status = $${values.length}`);
    }
    if (from) {
      values.push(from);
      where.push(`c.reported_time >= $${values.length}::timestamptz`);
    }
    if (to) {
      values.push(to);
      where.push(`c.reported_time <= $${values.length}::timestamptz`);
    }

    if (outbreakId) {
      values.push(outbreakId);
      where.push(`
        EXISTS (
          SELECT 1
          FROM disease_outbreaks o
          JOIN diseases d ON d.id = o.disease_id
          WHERE o.id = $${values.length}
            AND c.disease_type = d.name
            AND c.reported_time >= o.start_date
            AND (o.end_date IS NULL OR c.reported_time <= o.end_date)
        )
      `);
    }
    const whereSql = where.length ? `WHERE ${where.join(' AND ')}` : '';

    // Tß╗òng quan
    const [summary] = await this.dataSource.query(
      `
      SELECT
        COUNT(*)::int AS total_cases,
        COUNT(*) FILTER (WHERE c.region_id IS NOT NULL)::int AS matched_region,
        COUNT(*) FILTER (WHERE COALESCE(c.severity, 1) >= 3)::int AS high_severity,
        COUNT(*) FILTER (WHERE COALESCE(c.severity, 1) = 2)::int AS medium_severity,
        COUNT(*) FILTER (WHERE COALESCE(c.severity, 1) <= 1)::int AS low_severity,
        MIN(c.reported_time) AS min_time,
        MAX(c.reported_time) AS max_time
      FROM cases c
      ${whereSql};
      `,
      values,
    );

    // Top tß╗ënh
    const topRegions = await this.dataSource.query(
      `
      SELECT r.id, r."TinhThanh" AS name, COUNT(*)::int AS total
      FROM cases c
      JOIN regions r ON r.id = c.region_id
      ${whereSql}
      GROUP BY r.id, r."TinhThanh"
      ORDER BY total DESC
      LIMIT 10;
      `,
      values,
    );

    // Theo ng├áy (time series)
    const byDay = await this.dataSource.query(
      `
      SELECT
        date_trunc('day', c.reported_time)::date AS day,
        COUNT(*)::int AS total
      FROM cases c
      ${whereSql}
      GROUP BY day
      ORDER BY day ASC;
      `,
      values,
    );

    // Theo disease_type
    const byDisease = await this.dataSource.query(
      `
      SELECT c.disease_type, COUNT(*)::int AS total
      FROM cases c
      ${whereSql}
      GROUP BY c.disease_type
      ORDER BY total DESC;
      `,
      values,
    );

    // Theo status
    const byStatus = await this.dataSource.query(
      `
      SELECT CASE WHEN c.status = 'died' THEN 'deceased' ELSE c.status END AS status, COUNT(*)::int AS total
      FROM cases c
      ${whereSql}
      GROUP BY CASE WHEN c.status = 'died' THEN 'deceased' ELSE c.status END
      ORDER BY total DESC;
      `,
      values,
    );

    // Theo th├íng (monthly trend)
    const byMonth = await this.dataSource.query(
      `
      SELECT
        date_trunc('month', c.reported_time)::date AS month,
        COUNT(*)::int AS total
      FROM cases c
      ${whereSql}
      GROUP BY month
      ORDER BY month ASC;
      `,
      values,
    );

    // Theo tuß║ºn (weekly trend - last 12 weeks)
    const byWeek = await this.dataSource.query(
      `
      SELECT
        date_trunc('week', c.reported_time)::date AS week,
        COUNT(*)::int AS total
      FROM cases c
      ${whereSql}
      GROUP BY week
      ORDER BY week DESC
      LIMIT 12;
      `,
      values,
    );

    // So s├ính vß╗¢i kß╗│ tr╞░ß╗¢c (comparison)
    const now = new Date();
    const thirtyDaysAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
    const sixtyDaysAgo = new Date(now.getTime() - 60 * 24 * 60 * 60 * 1000);
    const yesterday = new Date(now.getTime() - 24 * 60 * 60 * 1000);
    const dayBeforeYesterday = new Date(
      now.getTime() - 2 * 24 * 60 * 60 * 1000,
    );
    const sevenDaysAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
    const fourteenDaysAgo = new Date(now.getTime() - 14 * 24 * 60 * 60 * 1000);

    const [comparison] = await this.dataSource.query(
      `
        SELECT
          COUNT(*) FILTER (WHERE c.reported_time >= $1)::int AS current_period,
          COUNT(*) FILTER (WHERE c.reported_time >= $2 AND c.reported_time < $1)::int AS previous_period,
          COUNT(*) FILTER (WHERE c.reported_time >= $3)::int AS today_cases,
          COUNT(*) FILTER (WHERE c.reported_time >= $4 AND c.reported_time < $3)::int AS yesterday_cases,
          COUNT(*) FILTER (WHERE c.reported_time >= $5)::int AS this_week_cases,
          COUNT(*) FILTER (WHERE c.reported_time >= $6 AND c.reported_time < $5)::int AS last_week_cases
        FROM cases c
        `,
      [
        thirtyDaysAgo.toISOString(),
        sixtyDaysAgo.toISOString(),
        yesterday.toISOString(),
        dayBeforeYesterday.toISOString(),
        sevenDaysAgo.toISOString(),
        fourteenDaysAgo.toISOString(),
      ],
    );

    return {
      summary,
      topRegions,
      byDay,
      byDisease,
      byStatus,
      byMonth,
      byWeek: byWeek.reverse(),
      comparison,
    };
  }

  /**
   * Get grid-based density data for risk visualization
   * Uses PostGIS to aggregate cases into grid cells
   */
  async getGridDensity(params: {
    diseaseType?: string;
    status?: string;
    from?: string;
    to?: string;
    gridSize?: number; // Grid cell size in degrees (default 0.1 ~ 11km)
    bounds?: { north: number; south: number; east: number; west: number };
    outbreakId?: string;
    includeArchived?: boolean;
  }) {
    const {
      diseaseType,
      status,
      from,
      to,
      gridSize = 0.1,
      bounds,
      outbreakId,
      includeArchived,
    } = params;

    const where: string[] = [];
    const values: any[] = [];

    if (!includeArchived) {
      where.push(`c.is_archived IS NOT TRUE`);
    }

    if (diseaseType) {
      values.push(diseaseType);
      where.push(`c.disease_type = $${values.length}`);
    }
    if (status) {
      values.push(this.normalizeStatusForDb(status));
      where.push(`c.status = $${values.length}`);
    }
    if (from) {
      values.push(from);
      where.push(`c.reported_time >= $${values.length}::timestamptz`);
    }
    if (to) {
      values.push(to);
      where.push(`c.reported_time <= $${values.length}::timestamptz`);
    }

    if (outbreakId) {
      values.push(outbreakId);
      where.push(`
        EXISTS (
          SELECT 1
          FROM disease_outbreaks o
          JOIN diseases d ON d.id = o.disease_id
          WHERE o.id = $${values.length}
            AND c.disease_type = d.name
            AND c.reported_time >= o.start_date
            AND (o.end_date IS NULL OR c.reported_time <= o.end_date)
        )
      `);
    }

    // Optional bounds filter
    if (bounds) {
      values.push(bounds.west, bounds.south, bounds.east, bounds.north);
      where.push(`ST_X(c.geom::geometry) >= $${values.length - 3}`);
      where.push(`ST_Y(c.geom::geometry) >= $${values.length - 2}`);
      where.push(`ST_X(c.geom::geometry) <= $${values.length - 1}`);
      where.push(`ST_Y(c.geom::geometry) <= $${values.length}`);
    }

    const whereSql = where.length ? `WHERE ${where.join(' AND ')}` : '';

    // Grid size parameter
    values.push(gridSize);
    const gridSizeParam = `$${values.length}`;

    // Use PostGIS snap-to-grid for aggregation
    const rows = await this.dataSource.query(
      `
      WITH grid_cases AS (
        SELECT
          c.id,
          c.disease_type,
          c.status,
          COALESCE(c.severity, 1) AS severity,
          FLOOR(ST_X(c.geom::geometry) / ${gridSizeParam}) * ${gridSizeParam} AS grid_x,
          FLOOR(ST_Y(c.geom::geometry) / ${gridSizeParam}) * ${gridSizeParam} AS grid_y
        FROM cases c
        ${whereSql}
      )
      SELECT
        grid_x,
        grid_y,
        COUNT(*)::int AS count,
        SUM(severity)::int AS total_severity,
        ROUND(AVG(severity)::numeric, 2)::float AS avg_severity,
        MAX(severity)::int AS max_severity,
        ARRAY_AGG(DISTINCT disease_type) AS diseases,
        ARRAY_AGG(DISTINCT status) AS statuses,
        jsonb_object_agg(
          disease_type,
          COALESCE(disease_counts.cnt, 0)
        ) AS disease_breakdown
      FROM grid_cases g
      LEFT JOIN LATERAL (
        SELECT disease_type AS dt, COUNT(*)::int AS cnt
        FROM grid_cases g2
        WHERE g2.grid_x = g.grid_x AND g2.grid_y = g.grid_y
        GROUP BY disease_type
      ) disease_counts ON TRUE
      GROUP BY grid_x, grid_y
      ORDER BY count DESC
      `,
      values,
    );

    // Alternative simpler query if the above has issues
    const simplifiedRows = await this.dataSource.query(
      `
      WITH grid_cases AS (
        SELECT
          c.id,
          c.disease_type,
          c.status,
          COALESCE(c.severity, 1) AS severity,
          FLOOR(ST_X(c.geom::geometry) / ${gridSizeParam}) * ${gridSizeParam} AS grid_x,
          FLOOR(ST_Y(c.geom::geometry) / ${gridSizeParam}) * ${gridSizeParam} AS grid_y
        FROM cases c
        ${whereSql}
      )
      SELECT
        grid_x,
        grid_y,
        COUNT(*)::int AS count,
        SUM(severity)::int AS total_severity,
        ROUND(AVG(severity)::numeric, 2)::float AS avg_severity,
        MAX(severity)::int AS max_severity,
        ARRAY_AGG(DISTINCT disease_type) AS diseases,
        ARRAY_AGG(DISTINCT status) AS statuses
      FROM grid_cases
      GROUP BY grid_x, grid_y
      ORDER BY count DESC
      `,
      values,
    );

    // Calculate risk levels based on count and severity
    const processedGrid = simplifiedRows.map((cell: any) => {
      const riskScore = cell.count * (cell.avg_severity || 1);
      let riskLevel: 'low' | 'medium' | 'high' | 'critical';

      if (riskScore >= 15 || cell.count >= 10) {
        riskLevel = 'critical';
      } else if (riskScore >= 8 || cell.count >= 5) {
        riskLevel = 'high';
      } else if (riskScore >= 3 || cell.count >= 2) {
        riskLevel = 'medium';
      } else {
        riskLevel = 'low';
      }

      return {
        bounds: {
          south: cell.grid_y,
          west: cell.grid_x,
          north: cell.grid_y + gridSize,
          east: cell.grid_x + gridSize,
        },
        count: cell.count,
        totalSeverity: cell.total_severity,
        avgSeverity: cell.avg_severity,
        maxSeverity: cell.max_severity,
        diseases: cell.diseases,
        statuses: Array.isArray(cell.statuses)
          ? cell.statuses.map((s: string) => this.normalizeStatusForApi(s))
          : cell.statuses,
        riskScore,
        riskLevel,
      };
    });

    return {
      gridSize,
      totalCells: processedGrid.length,
      cells: processedGrid,
      stats: {
        totalCases: processedGrid.reduce(
          (sum: number, c: any) => sum + c.count,
          0,
        ),
        criticalCells: processedGrid.filter(
          (c: any) => c.riskLevel === 'critical',
        ).length,
        highCells: processedGrid.filter((c: any) => c.riskLevel === 'high')
          .length,
        mediumCells: processedGrid.filter((c: any) => c.riskLevel === 'medium')
          .length,
        lowCells: processedGrid.filter((c: any) => c.riskLevel === 'low')
          .length,
      },
    };
  }

