    if (outbreakId) {
      values.push(outbreakId);
      where.push(`
        EXISTS (
          SELECT 1
          FROM disease_outbreaks o
          JOIN diseases d ON d.id = o.disease_id
          WHERE o.id = $${values.length}
            AND c.disease_type = d.name
            AND c.reported_time >= o.start_date
            AND (o.end_date IS NULL OR c.reported_time <= o.end_date)
        )
      `);
    }

    const whereSql = where.length ? `WHERE ${where.join(' AND ')}` : '';

    const safeMinPoints = Number.isFinite(minPoints)
      ? Math.max(1, Math.floor(minPoints))
      : 4;
    const epsDegrees =
      typeof clusterDistanceKm === 'number' &&
      Number.isFinite(clusterDistanceKm)
        ? Math.max(clusterDistanceKm, 0.001) / 111
        : Math.max(clusterDistance, 0.0001);
    const epsKmApprox = epsDegrees * 111;

    values.push(epsDegrees);
    const distParam = `$${values.length}`;
    values.push(safeMinPoints);
    const minPointsParam = `$${values.length}`;

    // Use ST_ClusterDBSCAN for spatial clustering
    const clusters = await this.dataSource.query(
      `
      WITH filtered AS (
        SELECT
          c.id,
          c.disease_type,
          c.status,
          COALESCE(c.severity, 1) AS severity,
          c.geom,
          c.reported_time
        FROM cases c
        ${whereSql}
      ),
      clustered AS (
        SELECT
          f.*,
          ST_ClusterDBSCAN(
            f.geom::geometry,
            eps := ${distParam},
            minpoints := ${minPointsParam}
          ) OVER (PARTITION BY f.disease_type) AS cluster_id
        FROM filtered f
      ),
      classified AS (
        SELECT
          a.*,
          n.neighbor_count,
          CASE
            WHEN a.cluster_id IS NULL THEN 'noise'
            WHEN n.neighbor_count >= ${minPointsParam} THEN 'core'
            ELSE 'border'
          END AS point_type
        FROM clustered a
        JOIN LATERAL (
          SELECT COUNT(*)::int AS neighbor_count
          FROM clustered b
          WHERE b.disease_type = a.disease_type
            AND ST_DWithin(a.geom::geometry, b.geom::geometry, ${distParam})
        ) n ON TRUE
      ),
      cluster_aggregates AS (
        SELECT
          disease_type,
          cluster_id,
          ST_Centroid(ST_Collect(geom::geometry)) AS centroid_geom,
          COUNT(*)::int AS count,
          ST_X(ST_Centroid(ST_Collect(geom::geometry)))::float AS center_lon,
          ST_Y(ST_Centroid(ST_Collect(geom::geometry)))::float AS center_lat,
          SUM(severity)::int AS total_severity,
          ROUND(AVG(severity)::numeric, 2)::float AS avg_severity,
          MAX(severity)::int AS max_severity,
          COUNT(*) FILTER (WHERE point_type = 'core')::int AS core_count,
          COUNT(*) FILTER (WHERE point_type = 'border')::int AS border_count,
          MIN(neighbor_count)::int AS min_neighbors,
          MAX(neighbor_count)::int AS max_neighbors,
          ARRAY_AGG(DISTINCT disease_type) AS diseases,
          ARRAY_AGG(DISTINCT status) AS statuses,
          MIN(reported_time) AS earliest_case,
          MAX(reported_time) AS latest_case
        FROM classified
        WHERE cluster_id IS NOT NULL
        GROUP BY disease_type, cluster_id
      ),
      cluster_max_distance AS (
        SELECT
          ca.disease_type,
          ca.cluster_id,
          COALESCE(
            MAX(
              ST_DistanceSphere(c.geom::geometry, ca.centroid_geom::geometry)
            ) / 1000.0,
            0
          )::float AS max_distance_km
        FROM cluster_aggregates ca
        JOIN classified c
          ON c.disease_type = ca.disease_type
         AND c.cluster_id = ca.cluster_id
        GROUP BY ca.disease_type, ca.cluster_id
      )
      SELECT
        ca.disease_type,
        CONCAT(ca.disease_type, ':', ca.cluster_id::text) AS cluster_key,
        ca.cluster_id,
        ca.count,
        ca.center_lon,
        ca.center_lat,
        cmd.max_distance_km,
        ca.total_severity,
        ca.avg_severity,
        ca.max_severity,
        ca.core_count,
        ca.border_count,
        ca.min_neighbors,
        ca.max_neighbors,
        ca.diseases,
        ca.statuses,
        ca.earliest_case,
        ca.latest_case
      FROM cluster_aggregates ca
      JOIN cluster_max_distance cmd
        ON cmd.disease_type = ca.disease_type
       AND cmd.cluster_id = ca.cluster_id
      ORDER BY ca.count DESC
      `,
      values,
    );

    const [noiseSummary] = await this.dataSource.query(
      `
      WITH filtered AS (
        SELECT
          c.id,
          c.disease_type,
          c.status,
          COALESCE(c.severity, 1) AS severity,
          c.geom,
          c.reported_time
        FROM cases c
        ${whereSql}
      ),
      clustered AS (
        SELECT
          f.*,
          ST_ClusterDBSCAN(
            f.geom::geometry,
            eps := ${distParam},
            minpoints := ${minPointsParam}
          ) OVER (PARTITION BY f.disease_type) AS cluster_id
        FROM filtered f
      )
      SELECT
        COUNT(*) FILTER (WHERE cluster_id IS NULL)::int AS noise_count,
        COUNT(*)::int AS total_points
      FROM clustered
      `,
      values,
    );

    const noisePoints = includeNoise
      ? await this.dataSource.query(
          `
          WITH filtered AS (
            SELECT
              c.id,
              c.disease_type,
              c.status,
              COALESCE(c.severity, 1) AS severity,
              c.geom,
              c.reported_time
            FROM cases c
            ${whereSql}
          ),
          clustered AS (
            SELECT
              f.*,
              ST_ClusterDBSCAN(
                f.geom::geometry,
                eps := ${distParam},
                minpoints := ${minPointsParam}
              ) OVER (PARTITION BY f.disease_type) AS cluster_id
            FROM filtered f
          )
          SELECT
            id,
            disease_type,
            CASE WHEN status = 'died' THEN 'deceased' ELSE status END AS status,
            severity,
            reported_time,
            ST_Y(geom::geometry)::float AS lat,
            ST_X(geom::geometry)::float AS lon
          FROM clustered
          WHERE cluster_id IS NULL
          ORDER BY reported_time DESC
          LIMIT 300
          `,
          values,
        )
      : [];

    // Calculate cluster severity with density-first logic.
    // Goal: a sparse cluster should not be marked high only because of a single severe case.
    const processedClusters = clusters.map((cluster: any) => {
      const count = Number(cluster.count || 0);
      const avgSeverity = Number(cluster.avg_severity || 1);
      const coreCount = Number(cluster.core_count || 0);

      // Density score: count (primary) + core ratio (secondary)
      // Range approx 1..3
      const countScore = Math.min(3, count / 4);
      const coreRatio = count > 0 ? coreCount / count : 0;
      const coreRatioScore = Math.min(3, 1 + coreRatio * 2);
      const densityScore = 0.7 * countScore + 0.3 * coreRatioScore;

      // Clinical score: average severity (not max severity)
      // Using avg avoids a single outlier case dominating the entire cluster.
      const clinicalScore = Math.min(3, Math.max(1, avgSeverity));

      // Final score is density-first.
      const severityScore = 0.75 * densityScore + 0.25 * clinicalScore;

      let clusterSeverity: number;
      if (count >= 8 && severityScore >= 2.35) {
        clusterSeverity = 3; // High
      } else if (count >= 3 && severityScore >= 1.6) {
        clusterSeverity = 2; // Medium
      } else {
        clusterSeverity = 1; // Low
      }

      return {
        id: cluster.cluster_key || cluster.cluster_id,
        count: cluster.count,
        center: {
          lat: cluster.center_lat,
          lon: cluster.center_lon,
        },
        spatial: {
          maxDistanceKm: Number(cluster.max_distance_km || 0),
        },
        severity: {
          total: cluster.total_severity,
          average: cluster.avg_severity,
          max: cluster.max_severity,
          combined: clusterSeverity,
          score: Number(severityScore.toFixed(3)),
        },
        diseases: cluster.diseases,
        statuses: Array.isArray(cluster.statuses)
          ? cluster.statuses.map((s: string) => this.normalizeStatusForApi(s))
          : cluster.statuses,
        dbscan: {
          pointTypeSummary: {
            core: cluster.core_count,
            border: cluster.border_count,
          },
          neighbors: {
            min: cluster.min_neighbors,
            max: cluster.max_neighbors,
          },
        },
        timeRange: {
          earliest: cluster.earliest_case,
          latest: cluster.latest_case,
        },
      };
    });

    return {
      algorithm: 'DBSCAN',
      parameters: {
        epsDegrees,
        epsKmApprox,
        minPoints: safeMinPoints,
        includeNoise,
      },
      totalClusters: processedClusters.length,
      totalCasesInClusters: processedClusters.reduce(
        (sum: number, c: any) => sum + c.count,
        0,
      ),
      noiseCount: noiseSummary?.noise_count ?? 0,
      totalCases: noiseSummary?.total_points ?? 0,
      clusters: processedClusters,
      noisePoints,
    };
  }

  /**
   * Reverse geocode coordinates to get address (commune, district, province)
   * First tries to match with local regions database for province, then uses Nominatim for full address
   */
  async reverseGeocode(
    lat: number,
    lon: number,
  ): Promise<ReverseGeocodeResult> {
    let regionId: number | undefined;
    let provinceName: string | undefined;

    // First, try to find matching region in our database (only has province level)
    try {
      const regionResult = await this.dataSource.query(
        `
        SELECT 
          r.id,
          r."TinhThanh" AS province
        FROM regions r
        WHERE ST_Within(
          ST_SetSRID(ST_MakePoint($1, $2), 4326),
          r.geom
        )
        LIMIT 1
        `,
        [lon, lat],
      );

      if (regionResult.length > 0) {
        regionId = regionResult[0].id;
        provinceName = regionResult[0].province;
      }
    } catch (error) {
      console.error('Database region lookup failed:', error);
    }

    // Use Nominatim (OpenStreetMap) for detailed reverse geocoding
    try {
      const response = await fetch(
        `https://nominatim.openstreetmap.org/reverse?format=json&lat=${lat}&lon=${lon}&accept-language=vi`,
        {
          headers: {
            'User-Agent': 'SafeZone/1.0',
          },
        },
      );

      if (response.ok) {
        const data = await response.json();
        const addr = data.address || {};

        // Extract Vietnamese administrative divisions
        const commune =
          addr.village || addr.suburb || addr.quarter || addr.hamlet;
        const district =
          addr.county || addr.city_district || addr.town || addr.municipality;
        const province =
          provinceName || addr.state || addr.province || addr.city;

        const parts = [commune, district, province].filter(Boolean);

        return {
          address:
            parts.length > 0
              ? parts.join(', ')
              : data.display_name || `${lat.toFixed(6)}, ${lon.toFixed(6)}`,
          commune,
          district,
          province,
          regionId,
        };
      }
    } catch (error) {
      console.error('Nominatim reverse geocode failed:', error);
    }

    // Final fallback: return coordinates as address with province if available
    return {
      address: provinceName || `${lat.toFixed(6)}, ${lon.toFixed(6)}`,
      province: provinceName,
      regionId,
    };
  }
}

