import {
  Controller,
  Get,
  Post,
  Delete,
  Param,
  Body,
  UseGuards,
  Request,
  Query,
} from '@nestjs/common';
import { AuthGuard } from '@nestjs/passport';
import { RolesGuard } from '../auth/guards/roles.guard';
import { Roles } from '../auth/decorators/roles.decorator';
import { UserRole } from '../auth/entities/user.entity';
import { NotificationService } from './notification.service';
import { CreateNotificationDto } from './dto/create-notification.dto';
import { EmailService } from './email.service';
import { NotificationType } from './entities/notification.entity';
import { ZoneService } from '../zone/zone.service';

@Controller('notifications')
export class NotificationController {
  constructor(
    private readonly notificationService: NotificationService,
    private readonly emailService: EmailService,
    private readonly zoneService: ZoneService,
  ) {}

  @UseGuards(AuthGuard('jwt'))
  @Get()
  async findAll(@Request() req) {
    return this.notificationService.findByUser(req.user.id);
  }

  @UseGuards(AuthGuard('jwt'))
  @Get('unread-count')
  async getUnreadCount(@Request() req) {
    const count = await this.notificationService.getUnreadCount(req.user.id);
    return { count };
  }

  @UseGuards(AuthGuard('jwt'))
  @Post(':id/read')
  async markAsRead(@Request() req, @Param('id') id: string) {
    return this.notificationService.markAsRead(id, req.user.id);
  }

  @UseGuards(AuthGuard('jwt'))
  @Post('read-all')
  async markAllAsRead(@Request() req) {
    await this.notificationService.markAllAsRead(req.user.id);
    return { success: true };
  }

  @UseGuards(AuthGuard('jwt'))
  @Delete(':id')
  async delete(@Request() req, @Param('id') id: string) {
    await this.notificationService.delete(id, req.user.id);
    return { success: true };
  }

  // Admin endpoints
  @Get('history')
  @UseGuards(AuthGuard('jwt'), RolesGuard)
  @Roles(UserRole.ADMIN, UserRole.HEALTH_AUTHORITY)
  async getBroadcastHistory() {
    return this.notificationService.findBroadcastHistory();
  }

  @Post('send')
  @UseGuards(AuthGuard('jwt'), RolesGuard)
  @Roles(UserRole.ADMIN, UserRole.HEALTH_AUTHORITY)
  async send(
    @Body()
    body: {
      title: string;
      body: string;
      type: string;
      zoneId?: string;
    },
  ) {
    // Send notification based on type (all users or specific zone)
    if (body.type === 'zone' && body.zoneId) {
      // Get zone info
      const zone = await this.zoneService.findOne(body.zoneId);

      // Send as broadcast with zone info in data
      return this.notificationService.createBroadcast(
        body.title,
        body.body,
        NotificationType.EPIDEMIC_ALERT,
        {
          zoneId: body.zoneId,
          zoneName: zone.name,
        },
      );
    } else {
      // Broadcast to all users
      return this.notificationService.createBroadcast(
        body.title,
        body.body,
        NotificationType.SYSTEM,
      );
    }
  }

  @UseGuards(AuthGuard('jwt'), RolesGuard)
  @Roles(UserRole.ADMIN, UserRole.HEALTH_AUTHORITY)
  @Post('broadcast')
  async createBroadcast(@Body() createNotificationDto: CreateNotificationDto) {
    // TODO: Add admin guard
    return this.notificationService.createBroadcast(
      createNotificationDto.title,
      createNotificationDto.body,
      createNotificationDto.type,
      createNotificationDto.data,
    );
  }

  @UseGuards(AuthGuard('jwt'))
  @Post('send/:userId')
  async sendToUser(
    @Param('userId') userId: string,
    @Body() createNotificationDto: CreateNotificationDto,
  ) {
    // TODO: Add admin guard
    return this.notificationService.sendToUser(
      userId,
      createNotificationDto.title,
      createNotificationDto.body,
      createNotificationDto.type,
      createNotificationDto.data,
    );
  }

  // Test email endpoint (for debugging)
  @Get('test-email')
  async testEmail(@Query('email') email: string) {
    if (!email) {
      return {
        success: false,
        message: 'Email parameter required. Use ?email=your@email.com',
      };
    }

    const result = await this.emailService.sendOtpEmail(
      email,
      '123456',
      'Test User',
    );
    return {
      success: result,
      message: result
        ? 'Email sent successfully! Check your inbox.'
        : 'Failed to send email. Check server logs.',
    };
  }
}

import { Injectable, Logger, OnModuleInit } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import * as admin from 'firebase-admin';
import * as path from 'path';
import * as fs from 'fs';

export interface PushNotificationPayload {
  title: string;
  body: string;
  data?: Record<string, string>;
  imageUrl?: string;
}

@Injectable()
export class PushService implements OnModuleInit {
  private readonly logger = new Logger(PushService.name);
  private isInitialized = false;

  constructor(private readonly configService: ConfigService) {}

  async onModuleInit() {
    await this.initializeFirebase();
  }

  private async initializeFirebase() {
    try {
      // Check if already initialized
      if (admin.apps.length > 0) {
        this.isInitialized = true;
        this.logger.log('Γ£à Firebase Admin already initialized');
        return;
      }

      // Try to load service account from file
      const serviceAccountPath = path.join(
        process.cwd(),
        'firebase-service-account.json',
      );

      if (fs.existsSync(serviceAccountPath)) {
        const serviceAccountContent = fs.readFileSync(
          serviceAccountPath,
          'utf8',
        );
        const serviceAccount = JSON.parse(serviceAccountContent);

        // Ensure private key is properly formatted
        if (serviceAccount.private_key) {
          serviceAccount.private_key = serviceAccount.private_key.replace(
            /\\n/g,
            '\n',
          );
        }

        admin.initializeApp({
          credential: admin.credential.cert(serviceAccount),
        });

        this.isInitialized = true;
        this.logger.log(
          `Γ£à Firebase Admin initialized with project: ${serviceAccount.project_id}`,
        );
      } else {
        // Try to load from environment variables
        const projectId = this.configService.get<string>('FIREBASE_PROJECT_ID');
        const clientEmail = this.configService.get<string>(
          'FIREBASE_CLIENT_EMAIL',
        );
        const privateKey = this.configService.get<string>(
          'FIREBASE_PRIVATE_KEY',
        );

        if (projectId && clientEmail && privateKey) {
          admin.initializeApp({
            credential: admin.credential.cert({
              projectId,
              clientEmail,
              privateKey: privateKey.replace(/\\n/g, '\n'),
            }),
          });

          this.isInitialized = true;
          this.logger.log(
            `Γ£à Firebase Admin initialized from env: ${projectId}`,
          );
        } else {
          this.logger.warn(
            'ΓÜá∩╕Å Firebase not configured. Push notifications disabled.',
          );
        }
      }
    } catch (error) {
      this.logger.error(`Γ¥î Failed to initialize Firebase: ${error.message}`);
    }
  }

  /**
   * Send push notification to a single device
   */
  async sendToDevice(
    token: string,
    payload: PushNotificationPayload,
  ): Promise<{ success: boolean; messageId?: string; error?: string }> {
    if (!this.isInitialized) {
      this.logger.warn(
        '[PUSH] Firebase not initialized, logging notification:',
      );
      this.logger.log(`  To: ${token.substring(0, 20)}...`);
      this.logger.log(`  Title: ${payload.title}`);
      this.logger.log(`  Body: ${payload.body}`);
      return { success: false, error: 'Firebase not initialized' };
    }

    try {
      const message: admin.messaging.Message = {
        token,
        notification: {
          title: payload.title,
          body: payload.body,
          imageUrl: payload.imageUrl,
        },
        data: payload.data,
        android: {
          priority: 'high',
          notification: {
            channelId: 'safezone_alerts',
            priority: 'high',
            defaultSound: true,
            defaultVibrateTimings: true,
          },
        },
        apns: {
          payload: {
            aps: {
              sound: 'default',
              badge: 1,
              contentAvailable: true,
            },
          },
        },
        webpush: {
          notification: {
            icon: '/icons/icon-192x192.png',
            badge: '/icons/badge-72x72.png',
          },
          fcmOptions: {
            link: payload.data?.link || '/',
          },
        },
      };

      const response = await admin.messaging().send(message);
      this.logger.log(`Γ£à Push sent successfully: ${response}`);
      return { success: true, messageId: response };
    } catch (error) {
      this.logger.error(`Γ¥î Failed to send push: ${error.message}`);

      // Handle invalid token
      if (
        error.code === 'messaging/invalid-registration-token' ||
        error.code === 'messaging/registration-token-not-registered'
      ) {
        return { success: false, error: 'invalid_token' };
      }

      return { success: false, error: error.message };
    }
  }

  /**
   * Send push notification to multiple devices
   */
  async sendToDevices(
    tokens: string[],
    payload: PushNotificationPayload,
  ): Promise<{
    successCount: number;
    failureCount: number;
    invalidTokens: string[];
  }> {
    if (!this.isInitialized || tokens.length === 0) {
      return {
        successCount: 0,
        failureCount: tokens.length,
        invalidTokens: [],
      };
    }

    const invalidTokens: string[] = [];
    let successCount = 0;
    let failureCount = 0;

    // Firebase batch limit is 500
    const batches = this.chunkArray(tokens, 500);

    for (const batch of batches) {
      try {
        const message: admin.messaging.MulticastMessage = {
          tokens: batch,
          notification: {
            title: payload.title,
            body: payload.body,
            imageUrl: payload.imageUrl,
          },
          data: payload.data,
          android: {
            priority: 'high',
            notification: {
              channelId: 'safezone_alerts',
              priority: 'high',
              defaultSound: true,
            },
          },
          apns: {
            payload: {
              aps: {
                sound: 'default',
                badge: 1,
              },
            },
          },
        };

        const response = await admin.messaging().sendEachForMulticast(message);

        successCount += response.successCount;
        failureCount += response.failureCount;

        // Collect invalid tokens
        response.responses.forEach((resp, idx) => {
          if (!resp.success && resp.error) {
            if (
              resp.error.code === 'messaging/invalid-registration-token' ||
              resp.error.code === 'messaging/registration-token-not-registered'
            ) {
              invalidTokens.push(batch[idx]);
            }
          }
        });
      } catch (error) {
        this.logger.error(`Γ¥î Batch send failed: ${error.message}`);
        failureCount += batch.length;
      }
    }

    this.logger.log(
      `≡ƒôè Push batch result: ${successCount} success, ${failureCount} failed`,
    );
    return { successCount, failureCount, invalidTokens };
  }

  /**
   * Send push notification to a topic (e.g., 'all', 'zone_123')
   */
  async sendToTopic(
    topic: string,
    payload: PushNotificationPayload,
  ): Promise<{ success: boolean; messageId?: string; error?: string }> {
    if (!this.isInitialized) {
      this.logger.warn(`[PUSH] Topic notification (not sent): ${topic}`);
      this.logger.log(`  Title: ${payload.title}`);
      this.logger.log(`  Body: ${payload.body}`);
      return { success: false, error: 'Firebase not initialized' };
    }

    try {
      const message: admin.messaging.Message = {
        topic,
        notification: {
          title: payload.title,
          body: payload.body,
          imageUrl: payload.imageUrl,
        },
        data: payload.data,
        android: {
          priority: 'high',
          notification: {
            channelId: 'safezone_alerts',
            priority: 'high',
            defaultSound: true,
          },
        },
        apns: {
          payload: {
            aps: {
              sound: 'default',
              badge: 1,
            },
          },
        },
      };

      const response = await admin.messaging().send(message);
      this.logger.log(`Γ£à Topic push sent: ${topic} -> ${response}`);
      return { success: true, messageId: response };
    } catch (error) {
      this.logger.error(
        `Γ¥î Failed to send to topic ${topic}: ${error.message}`,
      );
