  private chunkArray<T>(array: T[], size: number): T[][] {
    const chunks: T[][] = [];
    for (let i = 0; i < array.length; i += size) {
      chunks.push(array.slice(i, i + size));
    }
    return chunks;
  }
}

import { Injectable, Logger, OnModuleInit } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';

@Injectable()
export class SmsService implements OnModuleInit {
  private readonly logger = new Logger(SmsService.name);
  private twilioClient: any;
  private verifyServiceSid: string = '';
  private isConfigured = false;
  private devMode = false;
  private devOtpStore: Map<string, string> = new Map(); // Store OTP for dev mode

  constructor(private readonly configService: ConfigService) {}

  async onModuleInit() {
    const accountSid = this.configService.get<string>('TWILIO_ACCOUNT_SID');
    const authToken = this.configService.get<string>('TWILIO_AUTH_TOKEN');
    this.verifyServiceSid =
      this.configService.get<string>('TWILIO_VERIFY_SERVICE_SID') || '';

    // Check if dev mode is enabled (for testing without verified numbers)
    this.devMode = this.configService.get<string>('SMS_DEV_MODE') === 'true';

    this.logger.log(
      `Twilio Account SID: ${accountSid ? accountSid.substring(0, 10) + '...' : 'NOT SET'}`,
    );
    this.logger.log(
      `Twilio Verify Service SID: ${this.verifyServiceSid ? this.verifyServiceSid.substring(0, 10) + '...' : 'NOT SET'}`,
    );

    if (this.devMode) {
      this.logger.warn(
        'ΓÜá∩╕Å SMS DEV MODE ENABLED - OTP will be logged to console, use code "123456" to verify',
      );
    }

    if (accountSid && authToken && this.verifyServiceSid) {
      try {
        const twilio = require('twilio');
        this.twilioClient = twilio(accountSid, authToken);
        this.isConfigured = true;
        this.logger.log('Γ£à Twilio Verify service configured successfully!');
      } catch (error) {
        this.logger.error(
          'Γ¥î Failed to initialize Twilio client:',
          error.message,
        );
      }
    } else {
      this.logger.warn(
        'ΓÜá∩╕Å Twilio credentials not configured. SMS OTP will be logged to console only.',
      );
    }
  }

  /**
   * Send OTP via Twilio Verify API
   * This will send SMS automatically through Twilio's Verify service
   */
  async sendOtpSms(
    phone: string,
  ): Promise<{ success: boolean; message: string }> {
    // Format phone number (ensure it starts with +)
    const formattedPhone = phone.startsWith('+') ? phone : `+${phone}`;

    // Dev mode - skip real SMS, use fixed OTP "123456"
    if (this.devMode) {
      const otp = '123456';
      this.devOtpStore.set(formattedPhone, otp);
      this.logger.log('='.repeat(50));
      this.logger.warn('[≡ƒô▒ SMS DEV MODE - NO REAL SMS SENT]');
      this.logger.log(`To: ${formattedPhone}`);
      this.logger.warn(`OTP Code: ${otp}`);
      this.logger.log('='.repeat(50));
      return { success: true, message: 'OTP sent (dev mode - use 123456)' };
    }

    if (!this.isConfigured || !this.twilioClient) {
      // Fallback dev mode - generate random OTP for testing
      const otp = Math.floor(100000 + Math.random() * 900000).toString();
      this.devOtpStore.set(formattedPhone, otp);
      this.logger.log('='.repeat(50));
      this.logger.log('[SMS OTP - NOT CONFIGURED - DEV MODE]');
      this.logger.log(`To: ${formattedPhone}`);
      this.logger.log(`OTP Code: ${otp}`);
      this.logger.log('='.repeat(50));
      return { success: true, message: 'OTP sent (dev mode)' };
    }

    try {
      this.logger.log(
        `≡ƒô▒ Sending OTP to ${formattedPhone} via Twilio Verify...`,
      );

      const verification = await this.twilioClient.verify.v2
        .services(this.verifyServiceSid)
        .verifications.create({ to: formattedPhone, channel: 'sms' });

      this.logger.log(`Γ£à OTP sent successfully!`);
      this.logger.log(`   Status: ${verification.status}`);
      this.logger.log(`   SID: ${verification.sid}`);

      return { success: true, message: 'OTP sent successfully' };
    } catch (error) {
      this.logger.error(`Γ¥î Failed to send OTP to ${formattedPhone}`);
      this.logger.error(`   Error: ${error.message}`);

      // If Twilio fails (e.g., unverified number on trial), fallback to dev mode
      if (
        error.code === 21608 ||
        error.code === 21211 ||
        error.message?.includes('unverified')
      ) {
        const otp = '123456';
        this.devOtpStore.set(formattedPhone, otp);
        this.logger.warn(
          'ΓÜá∩╕Å Twilio trial limitation - falling back to dev mode',
        );
        this.logger.warn(`≡ƒô▒ Use OTP: ${otp} for phone ${formattedPhone}`);
        return {
          success: true,
          message: 'OTP sent (dev mode - Twilio trial limitation, use 123456)',
        };
      }

      if (error.code === 60200) {
        return { success: false, message: 'Invalid phone number format' };
      } else if (error.code === 60203) {
        return {
          success: false,
          message: 'Max send attempts reached. Please wait and try again.',
        };
      }

      return { success: false, message: error.message || 'Failed to send OTP' };
    }
  }

  /**
   * Verify OTP code via Twilio Verify API
   */
  async verifyOtp(
    phone: string,
    code: string,
  ): Promise<{ success: boolean; message: string }> {
    const formattedPhone = phone.startsWith('+') ? phone : `+${phone}`;

    // Dev mode - accept "123456" or the stored OTP
    if (this.devMode || !this.isConfigured || !this.twilioClient) {
      const storedOtp = this.devOtpStore.get(formattedPhone);
      if (code === '123456' || code === storedOtp) {
        this.logger.log('='.repeat(50));
        this.logger.log('[SMS VERIFY - DEV MODE]');
        this.logger.log(`Phone: ${formattedPhone}`);
        this.logger.log(`Code: ${code} - Γ£à ACCEPTED`);
        this.logger.log('='.repeat(50));
        this.devOtpStore.delete(formattedPhone);
        return { success: true, message: 'OTP verified (dev mode)' };
      }
      this.logger.warn(
        `[DEV MODE] Invalid OTP: ${code}, expected: 123456 or ${storedOtp}`,
      );
      return {
        success: false,
        message: 'Invalid OTP code. Use 123456 in dev mode.',
      };
    }

    try {
      this.logger.log(`≡ƒöÉ Verifying OTP for ${formattedPhone}...`);

      const verificationCheck = await this.twilioClient.verify.v2
        .services(this.verifyServiceSid)
        .verificationChecks.create({ to: formattedPhone, code: code });

      this.logger.log(`   Status: ${verificationCheck.status}`);

      if (verificationCheck.status === 'approved') {
        this.logger.log(`Γ£à OTP verified successfully!`);
        return { success: true, message: 'OTP verified successfully' };
      } else {
        this.logger.warn(
          `Γ¥î OTP verification failed: ${verificationCheck.status}`,
        );
        return { success: false, message: 'Invalid or expired OTP code' };
      }
    } catch (error) {
      this.logger.error(`Γ¥î Failed to verify OTP for ${formattedPhone}`);
      this.logger.error(`   Error: ${error.message}`);

      // Fallback to dev mode verification if Twilio fails
      const storedOtp = this.devOtpStore.get(formattedPhone);
      if (code === '123456' || code === storedOtp) {
        this.logger.warn(
          'ΓÜá∩╕Å Twilio verification failed, using dev mode fallback',
        );
        this.devOtpStore.delete(formattedPhone);
        return { success: true, message: 'OTP verified (dev mode fallback)' };
      }

      if (error.code === 60200) {
        return { success: false, message: 'Invalid phone number format' };
      } else if (error.code === 20404) {
        return {
          success: false,
          message: 'OTP expired or not found. Please request a new code.',
        };
      }

      return {
        success: false,
        message: error.message || 'Failed to verify OTP',
      };
    }
  }

  /**
   * Legacy method - now uses Twilio Verify
   */
  async sendSms(phone: string, message: string): Promise<boolean> {
    this.logger.log('='.repeat(50));
    this.logger.log('[SMS - Direct Send]');
    this.logger.log(`To: ${phone}`);
    this.logger.log(`Message: ${message}`);
    this.logger.log('='.repeat(50));
    return true;
  }
}

import {
  Controller,
  Get,
  Post,
  Patch,
  Delete,
  Body,
  Param,
  Query,
  UseGuards,
  Request,
} from '@nestjs/common';
import { AuthGuard } from '@nestjs/passport';
import { PostService } from './post.service';
import { CreatePostDto } from './dto/create-post.dto';
import { UpdatePostDto } from './dto/update-post.dto';
import { QueryPostDto } from './dto/query-post.dto';
import { ReactPostDto } from './dto/react-post.dto';
import { UpdatePostStatusDto } from './dto/update-status.dto';

@Controller('posts')
export class PostController {
  constructor(private readonly postService: PostService) {}

  // Create a new post (requires auth)
  @UseGuards(AuthGuard('jwt'))
  @Post()
  async create(@Request() req, @Body() createPostDto: CreatePostDto) {
    return this.postService.create(req.user.id, createPostDto);
  }

  // Get all posts (public - only approved posts)
  @Get()
  async findAll(@Query() queryDto: QueryPostDto) {
    return this.postService.findAll(queryDto);
  }

  // Get my posts (requires auth)
  @UseGuards(AuthGuard('jwt'))
  @Get('my-posts')
  async findMyPosts(@Request() req) {
    return this.postService.findByUser(req.user.id);
  }

  // Get post statistics (for admin dashboard)
  @Get('stats')
  async getStats() {
    return this.postService.getStats();
  }

  // Get single post by ID
  @Get(':id')
  async findOne(@Param('id') id: string) {
    return this.postService.findOne(id);
  }

  // Get user's reaction on a post
  @UseGuards(AuthGuard('jwt'))
  @Get(':id/my-reaction')
  async getMyReaction(@Request() req, @Param('id') id: string) {
    const reaction = await this.postService.getUserReaction(id, req.user.id);
    return { reaction };
  }

  // Update a post (requires auth, owner only)
  @UseGuards(AuthGuard('jwt'))
  @Patch(':id')
  async update(
    @Request() req,
    @Param('id') id: string,
    @Body() updatePostDto: UpdatePostDto,
  ) {
    const isAdmin = req.user.role === 'admin';
    return this.postService.update(id, req.user.id, updatePostDto, isAdmin);
  }

  // Update post status (admin only)
  @UseGuards(AuthGuard('jwt'))
  @Patch(':id/status')
  async updateStatus(
    @Request() req,
    @Param('id') id: string,
    @Body() updateStatusDto: UpdatePostStatusDto,
  ) {
    // TODO: Add admin guard
    return this.postService.updateStatus(
      id,
      updateStatusDto.status,
      updateStatusDto.adminNote,
    );
  }

  // React to a post (helpful/not helpful)
  @UseGuards(AuthGuard('jwt'))
  @Post(':id/react')
  async react(
    @Request() req,
    @Param('id') id: string,
    @Body() reactPostDto: ReactPostDto,
  ) {
    return this.postService.react(id, req.user.id, reactPostDto.type);
  }

  // Delete a post (requires auth, owner or admin)
  @UseGuards(AuthGuard('jwt'))
  @Delete(':id')
  async remove(@Request() req, @Param('id') id: string) {
    const isAdmin = req.user.role === 'admin';
    await this.postService.remove(id, req.user.id, isAdmin);
    return { success: true };
  }
}

import {
  Entity,
  PrimaryGeneratedColumn,
  Column,
  CreateDateColumn,
  UpdateDateColumn,
  ManyToOne,
  JoinColumn,
  Index,
} from 'typeorm';
import { Point } from 'geojson';
import { User } from '../../auth/entities/user.entity';

// Full workflow statuses matching WHO 4-layer confirmation process
export enum ReportStatus {
  SUBMITTED = 'submitted', // Ng╞░ß╗¥i d├ón vß╗½a gß╗¡i
  AUTO_VERIFIED = 'auto_verified', // Hß╗ç thß╗æng x├íc nhß║¡n tß╗▒ ─æß╗Öng
  UNDER_REVIEW = 'under_review', // Nh├ón vi├¬n y tß║┐ ─æang xem
  FIELD_VERIFICATION = 'field_verification', // ─Éang kiß╗âm tra thß╗▒c ─æß╗ïa
  CONFIRMED = 'confirmed', // X├íc nhß║¡n ca bß╗çnh
  REJECTED = 'rejected', // Kh├┤ng hß╗úp lß╗ç
  CLOSED = 'closed', // Ho├án tß║Ñt xß╗¡ l├╜
  // Keep old statuses for backward compatibility
  PENDING = 'pending',
  VERIFIED = 'verified',
  RESOLVED = 'resolved',
}

export type ReportType = 'case_report' | 'outbreak_alert';
export type SeverityLevel = 'low' | 'medium' | 'high' | 'critical';
export type PreliminaryResult = 'valid' | 'need_field_check' | 'invalid';
export type FieldVerificationResult = 'confirmed_suspected' | 'not_disease';
export type OfficialClassification =
  | 'suspected'
  | 'probable'
  | 'confirmed'
  | 'false_alarm';
export type ClosureAction =
  | 'monitoring'
  | 'isolation'
  | 'area_warning'
  | 'no_action';
export type LocationType =
  | 'school'
  | 'factory'
  | 'residential'
  | 'market'
  | 'hospital'
  | 'other';

export interface PatientInfo {
  fullName?: string;
  age?: number;
  yearOfBirth?: number;
  gender?: 'male' | 'female' | 'other';
  idNumber?: string;
  phone?: string;
  address?: string;
  occupation?: string;
  workplace?: string;
  symptomOnsetDate?: string;
  healthFacility?: string;
  isHospitalized?: boolean;
  travelHistory?: string;
  contactHistory?: string;
  underlyingConditions?: string[];
}

export interface AutoVerificationResult {
  phoneVerified: boolean;
  gpsValid: boolean;
  duplicateCheck: boolean;
  riskLevel: SeverityLevel;
  timestamp: string;
}

@Entity('reports')
export class Report {
  @PrimaryGeneratedColumn('uuid')
  id: string;

  // Report type: case_report or outbreak_alert
  @Column({ default: 'case_report' })
  reportType: ReportType;

  @Column()
  diseaseType: string;

  @Column('text')
  description: string;

  @Column({
    type: 'geometry',
    spatialFeatureType: 'Point',
    srid: 4326,
  })
  @Index({ spatial: true })
  location: Point;

  @Column({ nullable: true })
  address: string;

  // Reporter's location when submitting the report
  @Column({
    type: 'geometry',
    spatialFeatureType: 'Point',
    srid: 4326,
    nullable: true,
  })
  reporterLocation: Point;

  @Column('simple-array', { nullable: true })
  symptoms: string[];

  @Column({ default: 1 })
  affectedCount: number;

  @Column('simple-array', { nullable: true })
  imageUrls: string[];

  @Column({
    type: 'enum',
    enum: ReportStatus,
    default: ReportStatus.SUBMITTED,
  })
  status: ReportStatus;

  // Severity / urgency
  @Column({ default: 'medium' })
  severityLevel: SeverityLevel;

  @Column({ nullable: true })
  adminNote?: string;

  @Column({ nullable: true })
  verifiedAt: Date;

  @Column({ nullable: true })
  verifiedBy: string;

  // Detailed case report fields
  @Column({ default: false })
  isDetailedReport: boolean;

  @Column('jsonb', { nullable: true })
  patientInfo: PatientInfo;

  // Reporter info (stored for traceability)
  @Column({ nullable: true })
  reporterName: string;

  @Column({ nullable: true })
  reporterPhone: string;

  // Patient relation
  @Column({ default: true })
  isSelfReport: boolean;

  // Patient query columns
  @Column({ nullable: true })
  patientGender: string;

  @Column({ nullable: true })
  patientYearOfBirth: number;

  @Column({ nullable: true })
  patientPhone: string;

  @Column({ type: 'timestamp', nullable: true })
  symptomOnsetDate: Date;

  // Epidemiological info
  @Column({ nullable: true })
  hasContactWithPatient: boolean;

  @Column({ nullable: true })
  hasVisitedEpidemicArea: boolean;

  @Column({ nullable: true })
  hasSimilarCasesNearby: boolean;

  @Column({ nullable: true })
  estimatedNearbyCount: number;

  // Medical visit
  @Column({ nullable: true })
  hasVisitedDoctor: boolean;

  @Column({ nullable: true })
  hasTestResult: boolean;

  @Column({ type: 'text', nullable: true })
  testResultDescription: string;

  // Evidence URLs
  @Column('simple-array', { nullable: true })
  testResultImageUrls: string[];

  @Column('simple-array', { nullable: true })
  medicalCertImageUrls: string[];

  // Outbreak-specific fields
  @Column({ type: 'text', nullable: true })
  locationDescription: string;

  @Column({ nullable: true })
  locationType: LocationType;

  @Column({ nullable: true })
  suspectedDisease: string;

  @Column({ type: 'text', nullable: true })
  outbreakDescription: string;

  @Column({ type: 'timestamp', nullable: true })
  discoveryTime: Date;

  // ==================== MULTI-STEP VERIFICATION ====================

  // Step 1: Auto verification
  @Column({ type: 'timestamp', nullable: true })
  autoVerifiedAt: Date;

  @Column('jsonb', { nullable: true })
  autoVerificationResult: AutoVerificationResult;

  // Step 2: Preliminary review by local health station
  @Column({ nullable: true })
  preliminaryReviewBy: string;

  @Column({ type: 'timestamp', nullable: true })
  preliminaryReviewAt: Date;

  @Column({ type: 'text', nullable: true })
  preliminaryReviewNote: string;

  @Column({ nullable: true })
  preliminaryReviewResult: PreliminaryResult;

  // Step 3: Field verification
  @Column({ nullable: true })
  fieldVerifierId: string;

  @Column({ type: 'timestamp', nullable: true })
  fieldVerifiedAt: Date;

  @Column({ type: 'text', nullable: true })
  fieldVerificationNote: string;

  @Column({ nullable: true })
  fieldVerificationResult: FieldVerificationResult;

  // Step 4: Official confirmation (CDC / Ministry)
  @Column({ nullable: true })
  officialConfirmBy: string;

  @Column({ type: 'timestamp', nullable: true })
  officialConfirmAt: Date;

  @Column({ type: 'text', nullable: true })
  officialConfirmNote: string;

  @Column({ nullable: true })
  officialClassification: OfficialClassification;

  // Closure
  @Column({ type: 'timestamp', nullable: true })
  closedAt: Date;

  @Column({ nullable: true })
  closedBy: string;

  @Column({ type: 'text', nullable: true })
  closureNote: string;

  @Column({ nullable: true })
  closureAction: ClosureAction;

  // Consent
  @Column({ default: false })
  reporterConsent: boolean;

  // Device for spam prevention
  @Column({ nullable: true })
  deviceId: string;

  @ManyToOne(() => User, { eager: true })
  @JoinColumn({ name: 'userId' })
  user: User;

  @Column()
  userId: string;

  @CreateDateColumn()
  createdAt: Date;

  @UpdateDateColumn()
  updatedAt: Date;

  // Virtual properties for coordinates
  get latitude(): number {
    return this.location?.coordinates?.[1];
  }

  get longitude(): number {
    return this.location?.coordinates?.[0];
  }
}

// Status history entity for audit trail
@Entity('report_status_history')
export class ReportStatusHistory {
  @PrimaryGeneratedColumn('uuid')
  id: string;

  @Column()
  reportId: string;

  @Column({ nullable: true })
  previousStatus: string;

  @Column()
  newStatus: string;

  @Column({ nullable: true })
  changedBy: string;

  @Column({ nullable: true })
  changedByRole: string;

  @Column({ type: 'text', nullable: true })
  note: string;

  @Column('jsonb', { nullable: true })
  metadata: Record<string, any>;

  @CreateDateColumn()
  createdAt: Date;
}

import {
  Controller,
  Get,
  Post,
  Patch,
  Delete,
  Body,
  Param,
  Query,
  UseGuards,
  Request,
} from '@nestjs/common';
import { AuthGuard } from '@nestjs/passport';
import { ReportService } from './report.service';
import { CreateReportDto } from './dto/create-report.dto';
import { UpdateReportDto } from './dto/update-report.dto';
import { QueryReportDto } from './dto/query-report.dto';
import {
  UpdateStatusDto,
  PreliminaryReviewDto,
  FieldVerificationDto,
  OfficialConfirmationDto,
  CloseReportDto,
} from './dto/update-status.dto';
import { AuditLogService } from '../admin/audit-log.service';
import { AuditAction, AuditResource } from '../admin/entities/audit-log.entity';

@Controller('reports')
export class ReportController {
  constructor(
    private readonly reportService: ReportService,
    private readonly auditLogService: AuditLogService,
  ) {}

  // Report creation requires authentication. Email OTP is handled at client flow.
  @UseGuards(AuthGuard('jwt'))
  @Post()
  async create(@Request() req, @Body() createReportDto: CreateReportDto) {
    return this.reportService.create(req.user.id, createReportDto);
  }

  @Get()
  async findAll(@Query() queryDto: QueryReportDto) {
    return this.reportService.findAll(queryDto);
  }

  @UseGuards(AuthGuard('jwt'))
  @Get('my-reports')
  async findMyReports(@Request() req) {
    return this.reportService.findByUser(req.user.id);
  }

  @Get('nearby')
  async findNearby(
    @Query('lat') lat: number,
    @Query('lon') lon: number,
    @Query('radius') radius: number = 5,
  ) {
    return this.reportService.findNearby(lat, lon, radius);
  }

  @Get('stats')
  async getStats() {
    return this.reportService.getStats();
  }

  @Get(':id')
  async findOne(@Param('id') id: string) {
    return this.reportService.findOne(id);
  }

  // Get status history for a report
  @UseGuards(AuthGuard('jwt'))
  @Get(':id/history')
  async getStatusHistory(@Param('id') id: string) {
    return this.reportService.getStatusHistory(id);
  }

  @UseGuards(AuthGuard('jwt'))
  @Patch(':id')
  async update(
    @Request() req,
    @Param('id') id: string,
    @Body() updateReportDto: UpdateReportDto,
  ) {
    const isAdmin =
      req.user.role === 'admin' || req.user.role === 'health_authority';
    return this.reportService.update(id, req.user.id, updateReportDto, isAdmin);
  }

  // Legacy status update (backward compatible)
  @UseGuards(AuthGuard('jwt'))
  @Patch(':id/status')
  async updateStatus(
    @Request() req,
    @Param('id') id: string,
    @Body() updateStatusDto: UpdateStatusDto,
  ) {
    const result = await this.reportService.updateStatus(
      id,
      req.user.id,
      updateStatusDto.status,
      updateStatusDto.adminNote,
      updateStatusDto.createCase,
    );

    const action =
      updateStatusDto.status === 'verified' ||
      updateStatusDto.status === 'confirmed'
        ? AuditAction.APPROVE
        : updateStatusDto.status === 'rejected'
          ? AuditAction.REJECT
          : AuditAction.UPDATE;

    this.auditLogService.log(
      req.user.id,
      action,
      AuditResource.REPORT,
      id,
      `Status ΓåÆ ${updateStatusDto.status} for report #${id}`,
      {
        status: updateStatusDto.status,
        adminNote: updateStatusDto.adminNote,
        createCase: updateStatusDto.createCase,
      },
    );

    return result;
  }

  // Step 2: Preliminary review by local health authority
  @UseGuards(AuthGuard('jwt'))
  @Patch(':id/preliminary-review')
  async preliminaryReview(
    @Request() req,
    @Param('id') id: string,
    @Body() dto: PreliminaryReviewDto,
  ) {
    const result = await this.reportService.performPreliminaryReview(
      id,
      req.user.id,
      req.user.role,
      dto.result,
      dto.note,
    );

    this.auditLogService.log(
      req.user.id,
      dto.result === 'invalid' ? AuditAction.REJECT : AuditAction.APPROVE,
      AuditResource.REPORT,
      id,
      `Preliminary review: ${dto.result} for report #${id}`,
      { result: dto.result, note: dto.note },
    );

    return result;
  }

  // Step 3: Field verification
  @UseGuards(AuthGuard('jwt'))
  @Patch(':id/field-verify')
  async fieldVerify(
    @Request() req,
    @Param('id') id: string,
    @Body() dto: FieldVerificationDto,
  ) {
    const result = await this.reportService.performFieldVerification(
      id,
      req.user.id,
      req.user.role,
      dto.result,
      dto.note,
    );

    this.auditLogService.log(
      req.user.id,
      dto.result === 'not_disease' ? AuditAction.REJECT : AuditAction.APPROVE,
      AuditResource.REPORT,
      id,
      `Field verification: ${dto.result} for report #${id}`,
      { result: dto.result, note: dto.note },
    );

    return result;
  }

  // Step 4: Official confirmation (CDC / Ministry)
  @UseGuards(AuthGuard('jwt'))
  @Patch(':id/official-confirm')
  async officialConfirm(
    @Request() req,
    @Param('id') id: string,
    @Body() dto: OfficialConfirmationDto,
  ) {
    const result = await this.reportService.performOfficialConfirmation(
      id,
      req.user.id,
      req.user.role,
      dto.classification,
      dto.note,
      dto.createCase,
    );

    this.auditLogService.log(
      req.user.id,
      dto.classification === 'false_alarm'
        ? AuditAction.REJECT
        : AuditAction.APPROVE,
      AuditResource.REPORT,
      id,
      `Official confirmation: ${dto.classification} for report #${id}`,
      {
        classification: dto.classification,
        note: dto.note,
        publicationQueue: dto.classification !== 'false_alarm',
      },
    );

    return result;
  }

  // Step 5: Close report
  @UseGuards(AuthGuard('jwt'))
  @Patch(':id/close')
  async closeReport(
    @Request() req,
    @Param('id') id: string,
    @Body() dto: CloseReportDto,
  ) {
    const result = await this.reportService.closeReport(
      id,
      req.user.id,
      req.user.role,
      dto.action,
      dto.note,
    );

    this.auditLogService.log(
      req.user.id,
      AuditAction.UPDATE,
      AuditResource.REPORT,
      id,
      `Closed report #${id} with action: ${dto.action}`,
      { action: dto.action, note: dto.note },
    );

    return result;
  }

  @UseGuards(AuthGuard('jwt'))
  @Delete(':id')
  async remove(@Request() req, @Param('id') id: string) {
    const isAdmin =
      req.user.role === 'admin' || req.user.role === 'health_authority';
    return this.reportService.remove(id, req.user.id, isAdmin);
  }
}

import {
  Injectable,
  NotFoundException,
  ForbiddenException,
  BadRequestException,
  Inject,
  forwardRef,
  Logger,
} from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import {
  Report,
  ReportStatus,
  ReportStatusHistory,
} from './entities/report.entity';
import { CreateReportDto } from './dto/create-report.dto';
import { UpdateReportDto } from './dto/update-report.dto';
import { QueryReportDto } from './dto/query-report.dto';
import { NotificationService } from '../notification/notification.service';
import { NotificationType } from '../notification/entities/notification.entity';
import { GisService } from '../gis/gis.service';
import { ZoneService } from '../zone/zone.service';
import { User } from '../auth/entities/user.entity';

@Injectable()
export class ReportService {
  private readonly logger = new Logger(ReportService.name);

  constructor(
    @InjectRepository(Report)
    private reportRepository: Repository<Report>,
    @InjectRepository(ReportStatusHistory)
    private statusHistoryRepository: Repository<ReportStatusHistory>,
    private notificationService: NotificationService,
    @Inject(forwardRef(() => GisService))
    private gisService: GisService,
    private zoneService: ZoneService,
  ) {}

  // Log status change to audit trail
  private async logStatusChange(
    reportId: string,
    previousStatus: string | null | undefined,
    newStatus: string,
    changedBy?: string,
    changedByRole?: string,
    note?: string,
    metadata?: Record<string, any>,
  ): Promise<void> {
    try {
      const history = this.statusHistoryRepository.create({
        reportId,
        previousStatus: previousStatus ?? undefined,
        newStatus,
        changedBy,
        changedByRole,
        note,
        metadata,
      });
      await this.statusHistoryRepository.save(history);
    } catch (error) {
      console.error('Failed to log status change:', error);
    }
  }

  async create(
    userId: string,
    createReportDto: CreateReportDto,
  ): Promise<Report> {
    this.logger.log(
      `Create report request userId=${userId} reportType=${createReportDto.reportType ?? 'case_report'} disease=${createReportDto.diseaseType} imageCount=${createReportDto.imageUrls?.length ?? 0} testResultImageCount=${createReportDto.testResultImageUrls?.length ?? 0} medicalCertImageCount=${createReportDto.medicalCertImageUrls?.length ?? 0}`,
    );

    const {
      lat,
      lon,
      reporterLat,
      reporterLon,
      isDetailedReport,
      patientInfo,
      ...rest
    } = createReportDto;

    const normalizedDescription = (createReportDto.description || '').trim();
    if (!normalizedDescription) {
      throw new BadRequestException('M├┤ tß║ú b├ío c├ío kh├┤ng ─æ╞░ß╗úc ─æß╗â trß╗æng');
    }

    const reportType = createReportDto.reportType || 'case_report';

    const savedReport = await this.reportRepository.manager.transaction(
      async (manager) => {
        const txUserRepository = manager.getRepository(User);
        const txReportRepository = manager.getRepository(Report);
        const txStatusHistoryRepository =
          manager.getRepository(ReportStatusHistory);

        const user = await txUserRepository
          .createQueryBuilder('user')
          .setLock('pessimistic_write')
          .where('user.id = :userId', { userId })
          .getOne();

        if (!user) {
          throw new NotFoundException('Ng╞░ß╗¥i d├╣ng kh├┤ng tß╗ôn tß║íi');
        }

        if (user.isBlacklisted) {
          throw new ForbiddenException(
            'T├ái khoß║ún cß╗ºa bß║ín ─æ├ú bß╗ï kh├│a v├á kh├┤ng thß╗â gß╗¡i b├ío c├ío',
          );
        }

        if (!user.isEmailVerified && !user.isPhoneVerified) {
          throw new ForbiddenException(
            'Vui l├▓ng x├íc thß╗▒c OTP email hoß║╖c sß╗æ ─æiß╗çn thoß║íi tr╞░ß╗¢c khi gß╗¡i b├ío c├ío',
          );
        }

        const duplicateWindowMinutes = 10;
        const duplicateReport = await txReportRepository
          .createQueryBuilder('report')
          .where('report.userId = :userId', { userId })
          .andWhere('report.diseaseType = :diseaseType', {
            diseaseType: createReportDto.diseaseType,
          })
          .andWhere('report.reportType = :reportType', {
            reportType,
          })
          .andWhere(
            `ST_DWithin(
              report.location::geography,
              ST_SetSRID(ST_MakePoint(:lon, :lat), 4326)::geography,
              600
            )`,
            { lat, lon },
          )
          .andWhere(
            'LOWER(TRIM(report.description)) = LOWER(TRIM(:description))',
            { description: normalizedDescription },
          )
          .andWhere(
            `report.createdAt >= NOW() - INTERVAL '${duplicateWindowMinutes} minutes'`,
          )
          .orderBy('report.createdAt', 'DESC')
          .getOne();

        if (duplicateReport) {
          throw new BadRequestException(
            'Bß║ín vß╗½a gß╗¡i b├ío c├ío t╞░╞íng tß╗▒ trong v├ái ph├║t gß║ºn ─æ├óy. Vui l├▓ng tr├ính gß╗¡i tr├╣ng.',
          );
        }

        const recentHourlyCount = await txReportRepository
          .createQueryBuilder('report')
          .where('report.userId = :userId', { userId })
          .andWhere(`report.createdAt >= NOW() - INTERVAL '1 hour'`)
          .getCount();

        if (recentHourlyCount >= 8) {
          throw new BadRequestException(
            'Bß║ín ─æ├ú gß╗¡i qu├í nhiß╗üu b├ío c├ío trong 1 giß╗¥ qua. Vui l├▓ng thß╗¡ lß║íi sau.',
          );
        }

        if (createReportDto.deviceId) {
          const deviceHourlyCount = await txReportRepository
            .createQueryBuilder('report')
            .where('report.deviceId = :deviceId', {
              deviceId: createReportDto.deviceId,
            })
            .andWhere(`report.createdAt >= NOW() - INTERVAL '1 hour'`)
            .getCount();

          if (deviceHourlyCount >= 10) {
            throw new BadRequestException(
              'Thiß║┐t bß╗ï ─æ├ú gß╗¡i qu├í nhiß╗üu b├ío c├ío trong 1 giß╗¥ qua. Vui l├▓ng thß╗¡ lß║íi sau.',
            );
          }
        }

        const reportData: Partial<Report> = {
          ...rest,
          userId,
          description: normalizedDescription,
          status: ReportStatus.SUBMITTED,
          reportType,
          isDetailedReport: isDetailedReport || false,
          isSelfReport: createReportDto.isSelfReport ?? true,
          reporterName: createReportDto.reporterName,
          reporterPhone: createReportDto.reporterPhone,
          severityLevel: createReportDto.severityLevel || 'medium',
          reporterConsent: createReportDto.reporterConsent || false,
          deviceId: createReportDto.deviceId,
          // Epidemiological info
          hasContactWithPatient: createReportDto.hasContactWithPatient,
          hasVisitedEpidemicArea: createReportDto.hasVisitedEpidemicArea,
          hasSimilarCasesNearby: createReportDto.hasSimilarCasesNearby,
          estimatedNearbyCount: createReportDto.estimatedNearbyCount,
          // Medical info
          hasVisitedDoctor: createReportDto.hasVisitedDoctor,
          hasTestResult: createReportDto.hasTestResult,
          testResultDescription: createReportDto.testResultDescription,
          testResultImageUrls: createReportDto.testResultImageUrls,
          medicalCertImageUrls: createReportDto.medicalCertImageUrls,
          // Outbreak fields
          locationDescription: createReportDto.locationDescription,
          locationType: createReportDto.locationType as any,
          suspectedDisease: createReportDto.suspectedDisease,
          outbreakDescription: createReportDto.outbreakDescription,
          discoveryTime: createReportDto.discoveryTime
            ? new Date(createReportDto.discoveryTime)
            : undefined,
          patientInfo: patientInfo
            ? {
                fullName: patientInfo.fullName,
                age: patientInfo.age,
                yearOfBirth: patientInfo.yearOfBirth,
                gender: patientInfo.gender,
                idNumber: patientInfo.idNumber,
                phone: patientInfo.phone,
                address: patientInfo.address,
                occupation: patientInfo.occupation,
                workplace: patientInfo.workplace,
                symptomOnsetDate: patientInfo.symptomOnsetDate,
                healthFacility: patientInfo.healthFacility,
                isHospitalized: patientInfo.isHospitalized,
                travelHistory: patientInfo.travelHistory,
                contactHistory: patientInfo.contactHistory,
                underlyingConditions: patientInfo.underlyingConditions,
              }
            : undefined,
          // Patient query columns
          patientGender: patientInfo?.gender,
          patientYearOfBirth: patientInfo?.yearOfBirth,
          patientPhone: patientInfo?.phone,
          symptomOnsetDate: patientInfo?.symptomOnsetDate
            ? new Date(patientInfo.symptomOnsetDate)
            : undefined,
          location: {
            type: 'Point',
            coordinates: [lon, lat],
          },
        };

        if (
          createReportDto.hasSimilarCasesNearby === undefined ||
          createReportDto.estimatedNearbyCount === undefined
        ) {
          try {
            const zones = await this.zoneService.checkPointInZone(lat, lon);
            if (createReportDto.hasSimilarCasesNearby === undefined) {
              reportData.hasSimilarCasesNearby = zones.length > 0;
            }
            if (createReportDto.estimatedNearbyCount === undefined) {
              reportData.estimatedNearbyCount = zones.reduce(
                (sum, zone) => sum + (zone.caseCount || 0),
                0,
              );
            }
          } catch (error) {
            console.error('Failed to derive zone proximity for report:', error);
          }
        }

        if (reporterLat !== undefined && reporterLon !== undefined) {
          reportData.reporterLocation = {
            type: 'Point',
            coordinates: [reporterLon, reporterLat],
          };
        }

        const report = txReportRepository.create(reportData);
        const createdReport = await txReportRepository.save(report);

        const statusHistory = txStatusHistoryRepository.create({
          reportId: createdReport.id,
          previousStatus: undefined,
          newStatus: ReportStatus.SUBMITTED,
          changedBy: userId,
          changedByRole: 'user',
          note: 'B├ío c├ío ─æ╞░ß╗úc tß║ío',
        });
        await txStatusHistoryRepository.save(statusHistory);

        const now = new Date();
        const today = now.toISOString().slice(0, 10);
        const lastReportDay = user.lastReportDate
          ? user.lastReportDate instanceof Date
            ? user.lastReportDate.toISOString().slice(0, 10)
            : String(user.lastReportDate).slice(0, 10)
          : null;

        user.dailyReportCount =
          lastReportDay === today ? (user.dailyReportCount || 0) + 1 : 1;
        user.lastReportDate = now;
        await txUserRepository.save(user);

        return createdReport;
      },
    );

    // Note: Automatic verification has been removed.
    // Reports now go directly from SUBMITTED to waiting for preliminary review.
    // Admin must manually verify and approve the report.

    // Notify user
    const reportTypeLabel =
      createReportDto.reportType === 'outbreak_alert'
        ? 'Cß║únh b├ío ß╗ò dß╗ïch'
        : isDetailedReport
          ? 'B├ío c├ío chi tiß║┐t ca bß╗çnh'
          : 'B├ío c├ío dß╗ïch bß╗çnh';

    await this.notificationService.sendToUser(
      userId,
      `${reportTypeLabel} ─æ├ú ─æ╞░ß╗úc gß╗¡i`,
      `B├ío c├ío vß╗ü ${createReportDto.diseaseType} ─æ├ú ─æ╞░ß╗úc ghi nhß║¡n (M├ú: ${savedReport.id.substring(0, 8)}). C╞í quan y tß║┐ sß║╜ x├íc minh th├┤ng tin.`,
      NotificationType.REPORT_UPDATE,
      {
        reportId: savedReport.id,
        diseaseType: createReportDto.diseaseType,
        status: ReportStatus.SUBMITTED,
        reportType: createReportDto.reportType || 'case_report',
      },
    );

    this.logger.log(
      `Create report success reportId=${savedReport.id} userId=${userId} status=${savedReport.status}`,
    );

    return savedReport;
  }

  // Step 1: Auto verification (basic checks, no AI for now)
  private async performAutoVerification(report: Report): Promise<void> {
    const autoResult = {
      phoneVerified: true, // Already verified via PhoneVerifiedGuard
      gpsValid:
        report.location?.coordinates?.[0] !== 0 &&
        report.location?.coordinates?.[1] !== 0,
      duplicateCheck: true, // TODO: implement duplicate detection
      riskLevel: report.severityLevel || 'medium',
      timestamp: new Date().toISOString(),
    };

    report.autoVerifiedAt = new Date();
    report.autoVerificationResult = autoResult as any;
    report.status = ReportStatus.AUTO_VERIFIED;
    await this.reportRepository.save(report);

    await this.logStatusChange(
      report.id,
      ReportStatus.SUBMITTED,
      ReportStatus.AUTO_VERIFIED,
      undefined,
      'system',
      'Hß╗ç thß╗æng x├íc nhß║¡n tß╗▒ ─æß╗Öng',
      autoResult,
    );
  }

  // Step 2: Preliminary review by local health authority
  async performPreliminaryReview(
    reportId: string,
    reviewerId: string,
    reviewerRole: string,
    result: 'valid' | 'need_field_check' | 'invalid',
    note?: string,
  ): Promise<Report> {
    const report = await this.findOne(reportId);

    const previousStatus = report.status;
    report.preliminaryReviewBy = reviewerId;
    report.preliminaryReviewAt = new Date();
    report.preliminaryReviewNote = note || '';
    report.preliminaryReviewResult = result;

    if (result === 'invalid') {
      report.status = ReportStatus.REJECTED;
    } else if (result === 'need_field_check') {
      report.status = ReportStatus.FIELD_VERIFICATION;
    } else {
      report.status = ReportStatus.UNDER_REVIEW;
    }

    const updatedReport = await this.reportRepository.save(report);

    await this.logStatusChange(
      reportId,
      previousStatus,
      report.status,
      reviewerId,
      reviewerRole,
      note,
      { result },
    );

    // Notify reporter
    const resultMessages = {
      valid: 'B├ío c├ío ─æ├ú ─æ╞░ß╗úc x├íc nhß║¡n s╞í bß╗Ö. ─Éang chß╗¥ x├íc minh ch├¡nh thß╗⌐c.',
      need_field_check:
        'B├ío c├ío cß║ºn kiß╗âm tra thß╗▒c ─æß╗ïa. Nh├ón vi├¬n y tß║┐ sß║╜ ─æß║┐n x├íc minh.',
      invalid: `B├ío c├ío kh├┤ng hß╗úp lß╗ç.${note ? ` L├╜ do: ${note}` : ''}`,
    };

    await this.notificationService.sendToUser(
      report.userId,
      result === 'invalid'
        ? 'B├ío c├ío kh├┤ng ─æ╞░ß╗úc chß║Ñp nhß║¡n'
        : 'Cß║¡p nhß║¡t b├ío c├ío',
      resultMessages[result],
      NotificationType.REPORT_UPDATE,
      { reportId, status: report.status, result },
    );

    return updatedReport;
  }

  // Step 3: Field verification
  async performFieldVerification(
    reportId: string,
    verifierId: string,
    verifierRole: string,
    result: 'confirmed_suspected' | 'not_disease',
    note?: string,
  ): Promise<Report> {
    const report = await this.findOne(reportId);

    const previousStatus = report.status;
    report.fieldVerifierId = verifierId;
    report.fieldVerifiedAt = new Date();
    report.fieldVerificationNote = note || '';
    report.fieldVerificationResult = result;

    if (result === 'not_disease') {
      report.status = ReportStatus.REJECTED;
    } else {
      report.status = ReportStatus.CONFIRMED;
    }

    const updatedReport = await this.reportRepository.save(report);

    await this.logStatusChange(
      reportId,
      previousStatus,
      report.status,
      verifierId,
      verifierRole,
      note,
      { result },
    );

    const resultMessages = {
      confirmed_suspected:
        'Kß║┐t quß║ú kiß╗âm tra thß╗▒c ─æß╗ïa: Nghi ngß╗¥ ca bß╗çnh. ─Éang chß╗¥ x├íc nhß║¡n ch├¡nh thß╗⌐c.',
      not_disease: `Kß║┐t quß║ú kiß╗âm tra: Kh├┤ng li├¬n quan ─æß║┐n dß╗ïch bß╗çnh.${note ? ` Ghi ch├║: ${note}` : ''}`,
    };

    await this.notificationService.sendToUser(
      report.userId,
      result === 'not_disease'
        ? 'Kß║┐t quß║ú kiß╗âm tra thß╗▒c ─æß╗ïa'
        : 'Cß║¡p nhß║¡t b├ío c├ío',
      resultMessages[result],
      NotificationType.REPORT_UPDATE,
      { reportId, status: report.status, result },
    );

    return updatedReport;
  }

  // Step 4: Official confirmation (CDC / Ministry)
  async performOfficialConfirmation(
    reportId: string,
    confirmerId: string,
    confirmerRole: string,
    classification: 'suspected' | 'probable' | 'confirmed' | 'false_alarm',
    note?: string,
    _createCase?: boolean,
  ): Promise<{ report: Report; case?: any }> {
    const report = await this.findOne(reportId);

    const previousStatus = report.status;
    report.officialConfirmBy = confirmerId;
    report.officialConfirmAt = new Date();
    report.officialConfirmNote = note || '';
    report.officialClassification = classification;

    if (classification === 'false_alarm') {
      report.status = ReportStatus.REJECTED;
    } else {
      // Keep approved reports in publication queue until official publishing flow is completed.
      report.status = ReportStatus.PENDING;
    }

    const updatedReport = await this.reportRepository.save(report);

    await this.logStatusChange(
      reportId,
      previousStatus,
      report.status,
      confirmerId,
      confirmerRole,
      note,
      { classification },
    );

    let createdCase: any = undefined;

    // Optional: create a case on the GIS map.
    // Business rule: only allow creating a case from a detailed report.
    if (
      _createCase &&
      report.isDetailedReport &&
      classification !== 'false_alarm'
    ) {
      const lat = Number(report.latitude);
      const lon = Number(report.longitude);
      const hasValidCoords =
        Number.isFinite(lat) &&
        Number.isFinite(lon) &&
        Math.abs(lat) <= 90 &&
        Math.abs(lon) <= 180 &&
        !(lat === 0 && lon === 0);

      if (!hasValidCoords) {
        throw new BadRequestException(
          'Kh├┤ng thß╗â tß║ío ca bß╗çnh v├¼ tß╗ìa ─æß╗Ö b├ío c├ío kh├┤ng hß╗úp lß╗ç',
        );
      }

      const severityMap: Record<string, number> = {
        low: 1,
        medium: 1,
        high: 2,
        critical: 3,
      };

      const patientName =
        report.patientInfo?.fullName || report.reporterName || undefined;
      const patientAge =
        typeof report.patientInfo?.age === 'number'
          ? report.patientInfo?.age
          : undefined;
      const patientGender = report.patientInfo?.gender || undefined;

      const evidenceCount =
        (report.imageUrls?.length || 0) +
        (report.testResultImageUrls?.length || 0) +
        (report.medicalCertImageUrls?.length || 0);

      createdCase = await this.gisService.createCase({
        disease_type: report.diseaseType,
        status: 'suspected',
        severity: severityMap[String(report.severityLevel || 'medium')] || 1,
        reported_time: (report.createdAt || new Date()).toISOString(),
        lat,
        lon,
        patient_name: patientName,
        patient_age: patientAge,
        patient_gender: patientGender,
        notes:
          `From report ${report.id}. ` +
          `Official classification: ${classification}. ` +
          `Evidence images: ${evidenceCount}. ` +
          (note ? `Official note: ${note}` : ''),
      });
    }

    const classLabels = {
      suspected: 'Nghi ngß╗¥',
      probable: 'C├│ thß╗â',
      confirmed: 'X├íc nhß║¡n',
      false_alarm: 'B├ío ─æß╗Öng giß║ú',
    };

    await this.notificationService.sendToUser(
      report.userId,
      `Kß║┐t quß║ú x├íc nhß║¡n ch├¡nh thß╗⌐c: ${classLabels[classification]}`,
      classification === 'false_alarm'
        ? `B├ío c├ío vß╗ü ${report.diseaseType} ─æ╞░ß╗úc x├íc nhß║¡n l├á b├ío ─æß╗Öng giß║ú.${note ? ` Ghi ch├║: ${note}` : ''}`
        : `B├ío c├ío vß╗ü ${report.diseaseType} ─æ├ú qua duyß╗çt v├á ─æang ß╗ƒ h├áng chß╗¥ c├┤ng bß╗æ ch├¡nh thß╗⌐c.${note ? ` Ghi ch├║: ${note}` : ''}`,
      NotificationType.REPORT_UPDATE,
      { reportId, status: report.status, classification },
    );

    return { report: updatedReport, case: createdCase };
  }

  // Step 5: Close report
  async closeReport(
