    });
  }

  async findAll(queryDto: QueryReportDto): Promise<{
    data: Report[];
    total: number;
    page: number;
    limit: number;
  }> {
    const {
      page = 1,
      limit = 20,
      status,
      diseaseType,
      startDate,
      endDate,
    } = queryDto;

    const queryBuilder = this.reportRepository
      .createQueryBuilder('report')
      .leftJoinAndSelect('report.user', 'user')
      .orderBy('report.createdAt', 'DESC');

    if (status) {
      queryBuilder.andWhere('report.status = :status', { status });
    }

    if (diseaseType) {
      queryBuilder.andWhere('report.diseaseType = :diseaseType', {
        diseaseType,
      });
    }

    if (startDate) {
      queryBuilder.andWhere('report.createdAt >= :startDate', { startDate });
    }

    if (endDate) {
      queryBuilder.andWhere('report.createdAt <= :endDate', { endDate });
    }

    const total = await queryBuilder.getCount();
    const data = await queryBuilder
      .skip((page - 1) * limit)
      .take(limit)
      .getMany();

    data.forEach((report) => {
      if (report.user) {
        delete report.user.password;
      }
    });

    return { data, total, page, limit };
  }

  async findByUser(userId: string): Promise<Report[]> {
    const reports = await this.reportRepository.find({
      where: { userId },
      order: { createdAt: 'DESC' },
    });

    reports.forEach((report) => {
      if (report.user) {
        delete report.user.password;
      }
    });

    return reports;
  }

  async findOne(id: string): Promise<Report> {
    const report = await this.reportRepository.findOne({
      where: { id },
      relations: ['user'],
    });

    if (!report) {
      throw new NotFoundException('B├ío c├ío kh├┤ng tß╗ôn tß║íi');
    }

    if (report.user) {
      delete report.user.password;
    }

    return report;
  }

  async findNearby(
    lat: number,
    lon: number,
    radiusKm: number = 5,
  ): Promise<Report[]> {
    const reports = await this.reportRepository
      .createQueryBuilder('report')
      .where(
        `ST_DWithin(
          report.location::geography,
          ST_SetSRID(ST_MakePoint(:lon, :lat), 4326)::geography,
          :radius
        )`,
        { lat, lon, radius: radiusKm * 1000 },
      )
      .andWhere('report.status IN (:...statuses)', {
        statuses: [
          ReportStatus.CONFIRMED,
          ReportStatus.PENDING,
          ReportStatus.VERIFIED,
        ],
      })
      .andWhere('report.reportType = :reportType', {
        reportType: 'case_report',
      })
      .orderBy('report.createdAt', 'DESC')
      .getMany();

    return reports;
  }

  async update(
    id: string,
    userId: string,
    updateReportDto: UpdateReportDto,
    isAdmin: boolean = false,
  ): Promise<Report> {
    const report = await this.findOne(id);

    if (!isAdmin && report.userId !== userId) {
      throw new ForbiddenException('Bß║ín kh├┤ng c├│ quyß╗ün cß║¡p nhß║¡t b├ío c├ío n├áy');
    }

    if (!isAdmin) {
      delete updateReportDto.status;
      delete updateReportDto.adminNote;
    }

    Object.assign(report, updateReportDto);
    return this.reportRepository.save(report);
  }

