        },
        [ReportStatus.REJECTED]: {
          title: 'B├ío c├ío kh├┤ng ─æ╞░ß╗úc chß║Ñp nhß║¡n',
          body: `B├ío c├ío cß╗ºa bß║ín vß╗ü ${report.diseaseType} kh├┤ng ─æ╞░ß╗úc chß║Ñp nhß║¡n.${adminNote ? ` L├╜ do: ${adminNote}` : ''}`,
