  async remove(
    id: string,
    userId: string,
    isAdmin: boolean = false,
  ): Promise<void> {
    const report = await this.findOne(id);

    if (!isAdmin && report.userId !== userId) {
      throw new ForbiddenException('Bß║ín kh├┤ng c├│ quyß╗ün x├│a b├ío c├ío n├áy');
    }

    await this.reportRepository.remove(report);
  }

  async getStats(): Promise<{
    total: number;
    submitted: number;
    autoVerified: number;
    underReview: number;
    fieldVerification: number;
    confirmed: number;
    rejected: number;
    closed: number;
    pending: number;
    verified: number;
    byDisease: Record<string, number>;
    byReportType: Record<string, number>;
  }> {
    const total = await this.reportRepository.count();
    const submitted = await this.reportRepository.count({
      where: { status: ReportStatus.SUBMITTED },
    });
    const autoVerified = await this.reportRepository.count({
      where: { status: ReportStatus.AUTO_VERIFIED },
    });
    const underReview = await this.reportRepository.count({
      where: { status: ReportStatus.UNDER_REVIEW },
    });
    const fieldVerification = await this.reportRepository.count({
      where: { status: ReportStatus.FIELD_VERIFICATION },
    });
    const confirmed = await this.reportRepository.count({
      where: { status: ReportStatus.CONFIRMED },
    });
    const rejected = await this.reportRepository.count({
      where: { status: ReportStatus.REJECTED },
    });
    const closed = await this.reportRepository.count({
      where: { status: ReportStatus.CLOSED },
    });
    const pending = await this.reportRepository.count({
      where: { status: ReportStatus.PENDING },
    });
    const verified = await this.reportRepository.count({
      where: { status: ReportStatus.VERIFIED },
    });

    const byDiseaseRaw = await this.reportRepository
      .createQueryBuilder('report')
      .select('report.diseaseType', 'diseaseType')
      .addSelect('COUNT(*)', 'count')
      .groupBy('report.diseaseType')
      .getRawMany();

    const byDisease = byDiseaseRaw.reduce(
      (acc, item) => {
        acc[item.diseaseType] = parseInt(item.count);
        return acc;
      },
      {} as Record<string, number>,
    );

    const byTypeRaw = await this.reportRepository
      .createQueryBuilder('report')
      .select('report.reportType', 'reportType')
      .addSelect('COUNT(*)', 'count')
      .groupBy('report.reportType')
      .getRawMany();

    const byReportType = byTypeRaw.reduce(
      (acc, item) => {
        acc[item.reportType || 'case_report'] = parseInt(item.count);
        return acc;
      },
      {} as Record<string, number>,
    );

    return {
      total,
      submitted,
      autoVerified,
      underReview,
      fieldVerification,
      confirmed,
      rejected,
      closed,
      pending,
      verified,
      byDisease,
      byReportType,
    };
  }
}

import {
  Entity,
  PrimaryGeneratedColumn,
  Column,
  CreateDateColumn,
  UpdateDateColumn,
  Index,
} from 'typeorm';
import { Point } from 'geojson';

export enum RiskLevel {
  LOW = 'low',
  MEDIUM = 'medium',
  HIGH = 'high',
  CRITICAL = 'critical',
}

export enum ZoneLifecycleStatus {
  PROPOSED = 'proposed',
  PENDING_APPROVAL = 'pending_approval',
  APPROVED = 'approved',
  REJECTED = 'rejected',
  CLOSED = 'closed',
}

export enum ZoneSource {
  MANUAL = 'manual',
  DBSCAN = 'dbscan',
}

@Entity('epidemic_zones')
export class EpidemicZone {
  @PrimaryGeneratedColumn('uuid')
  id: string;

  @Column()
  name: string;

  @Column()
  diseaseType: string;

  @Column({
    type: 'geometry',
    spatialFeatureType: 'Point',
    srid: 4326,
  })
  @Index({ spatial: true })
  center: Point;

  @Column('float')
  radiusKm: number;

  @Column({
    type: 'enum',
    enum: RiskLevel,
    default: RiskLevel.LOW,
  })
  riskLevel: RiskLevel;

  @Column({ default: 0 })
  caseCount: number;

  @Column('text', { nullable: true })
  description: string | null;

  @Column({ default: true })
  isActive: boolean;

  @Column({
    type: 'enum',
    enum: ZoneLifecycleStatus,
    default: ZoneLifecycleStatus.APPROVED,
  })
  lifecycleStatus: ZoneLifecycleStatus;

  @Column({
    type: 'enum',
    enum: ZoneSource,
    default: ZoneSource.MANUAL,
  })
  source: ZoneSource;

  @Column('float', { nullable: true })
  proposalConfidence: number | null;

  @Column('jsonb', { nullable: true })
  proposalMetadata: Record<string, any> | null;

  @Column({ type: 'timestamptz', nullable: true })
  proposedAt: Date | null;

  @Column({ type: 'varchar', nullable: true })
  proposedBy: string | null;

  @Column({ type: 'timestamptz', nullable: true })
  reviewedAt: Date | null;

  @Column({ type: 'varchar', nullable: true })
  reviewedBy: string | null;

  @Column('text', { nullable: true })
  reviewNote: string | null;

  @Column({ type: 'timestamptz', nullable: true })
  startDate: Date | null;

  @Column({ type: 'timestamptz', nullable: true })
  endDate: Date | null;

  @CreateDateColumn()
  createdAt: Date;

  @UpdateDateColumn()
  updatedAt: Date;

  // Virtual properties
  get latitude(): number {
    return this.center?.coordinates?.[1];
  }

  get longitude(): number {
    return this.center?.coordinates?.[0];
  }
}

import {
  Controller,
  Get,
  Post,
  Patch,
  Delete,
  Body,
  Param,
  Query,
  UseGuards,
  Request,
} from '@nestjs/common';
import { AuthGuard } from '@nestjs/passport';
import { RolesGuard } from '../auth/guards/roles.guard';
import { Roles } from '../auth/decorators/roles.decorator';
import { UserRole } from '../auth/entities/user.entity';
import { ZoneService } from './zone.service';
import { CreateZoneDto } from './dto/create-zone.dto';
import { UpdateZoneDto } from './dto/update-zone.dto';
import { NotificationService } from '../notification/notification.service';
import { ProposeZonesDbscanDto } from './dto/propose-zones-dbscan.dto';
import { ReviewZoneProposalDto } from './dto/review-zone-proposal.dto';
import {
  ZoneLifecycleStatus,
  ZoneSource,
} from './entities/epidemic-zone.entity';

@Controller('zones')
export class ZoneController {
  constructor(
    private readonly zoneService: ZoneService,
    private readonly notificationService: NotificationService,
  ) {}

  @Post()
  @UseGuards(AuthGuard('jwt'), RolesGuard)
  @Roles(UserRole.ADMIN, UserRole.HEALTH_AUTHORITY)
  async create(@Body() createZoneDto: CreateZoneDto, @Request() req: any) {
    const actorId = req?.user?.sub || req?.user?.id;
    return this.zoneService.create(createZoneDto, actorId);
  }

  @Post('proposals/dbscan')
  @UseGuards(AuthGuard('jwt'), RolesGuard)
  @Roles(UserRole.ADMIN, UserRole.HEALTH_AUTHORITY)
  async proposeFromDbscan(
    @Body() dto: ProposeZonesDbscanDto,
    @Request() req: any,
  ) {
    const actorId = req?.user?.sub || req?.user?.id;
    return this.zoneService.proposeFromDbscan({
      ...dto,
      proposedBy: actorId,
    });
  }

  @Post('proposals/dbscan/preview')
  @UseGuards(AuthGuard('jwt'), RolesGuard)
  @Roles(UserRole.ADMIN, UserRole.HEALTH_AUTHORITY)
  async previewDbscanProposals(
    @Body() dto: ProposeZonesDbscanDto,
  ): Promise<any> {
    return this.zoneService.previewDbscanProposals(dto);
  }

  @Get()
  async findAll(
    @Query('all') all: string,
    @Query('active') active?: string,
    @Query('lifecycleStatus') lifecycleStatus?: ZoneLifecycleStatus,
    @Query('source') source?: ZoneSource,
  ) {
    const onlyActive =
      active === 'true' ? true : active === 'false' ? false : all !== 'true';

    return this.zoneService.findAll({
      onlyActive,
      lifecycleStatus,
      source,
    });
  }

  @Get('nearby')
  async findNearby(
    @Query('lat') lat: number,
    @Query('lon') lon: number,
    @Query('radius') radius: number = 10,
  ) {
    return this.zoneService.findNearby(lat, lon, radius);
  }

  @Get('check')
  async checkPointInZone(@Query('lat') lat: number, @Query('lon') lon: number) {
    const zones = await this.zoneService.checkPointInZone(lat, lon);
    return {
      inZone: zones.length > 0,
      zones,
    };
  }

  /**
   * Check if user is in danger zone and send push notification alert
   * Should be called periodically from mobile app when location changes
   */
  @UseGuards(AuthGuard('jwt'))
  @Post('check-location')
  async checkLocationAndAlert(
    @Request() req,
    @Body('lat') lat: number,
    @Body('lon') lon: number,
  ) {
    const userId = req.user.sub;
    const zones = await this.zoneService.checkPointInZone(lat, lon);

    if (zones.length > 0) {
      // User is in danger zone - send push notification
      const highestRiskZone = zones[0]; // Zones are sorted by risk level DESC

      await this.notificationService.sendZoneEntryAlert(
        userId,
        highestRiskZone.name,
        highestRiskZone.diseaseType,
        highestRiskZone.riskLevel as 'low' | 'medium' | 'high' | 'critical',
        highestRiskZone.id,
      );
    }

    return {
      inZone: zones.length > 0,
      zones,
      alertSent: zones.length > 0,
    };
  }

  @Get('stats')
  async getStats() {
    return this.zoneService.getStats();
  }

  @Get(':id')
  async findOne(@Param('id') id: string) {
    return this.zoneService.findOne(id);
  }

  @Patch(':id')
